INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:21  
    
  DL n.º 194/2012, de 23 de Agosto  (versão actualizada) LEI ORGÂNICA DA AUTORIDADE DE SEGURANÇA ALIMENTAR E ECONÓMICA    
    
 
  
                         
                          
SUMÁRIOAprova a orgânica da Autoridade de Segurança Alimentar e Económica 
Decreto-Lei n.º 194/2012, de 23 de agosto 
  No âmbito do Compromisso Eficiência, o XIX Governo Constitucional determinou as linhas gerais do Plano de Redução e Melhoria da Administração Central (PREMAC), afirmando que o primeiro e mais importante impulso do Plano deveria, desde logo, ser dado no processo de preparação das leis orgânicas dos ministérios e dos respetivos serviços. 
  Trata-se de algo absolutamente estruturante, por um lado, para o início de uma nova fase da reforma da Administração Pública no sentido de a tornar eficiente e racional na utilização dos recursos públicos e, por outro, para o cumprimento dos objetivos de redução da despesa pública a que o País está vinculado. Com efeito, mais do que nunca, a concretização simultânea dos objetivos de racionalização das estruturas do Estado e de melhor utilização dos seus recursos humanos é crucial no processo de modernização e de otimização do funcionamento da Administração Pública. 
  Importava decididamente repensar e reorganizar a estrutura do Estado no sentido de lhe dar uma maior coerência e capacidade de resposta no desempenho das funções que deverá assegurar, eliminando redundâncias e reduzindo substancialmente os seus custos de funcionamento. 
  Neste contexto, foi aprovada a Lei Orgânica do Ministério da Economia e do Emprego (MEE) pelo Decreto-Lei n.º 126-C/2011, de 29 de dezembro, que procede à reestruturação da Autoridade de Segurança Alimentar e Económica (ASAE), serviço que sucede igualmente nas atribuições da Comissão de Aplicação de Coimas em Matéria Económica e de Publicidade no domínio da economia. 
  Este serviço da administração direta do Estado tem por missão a fiscalização e prevenção do cumprimento da legislação reguladora do exercício das atividades económicas, nos setores alimentar e não alimentar, bem como a avaliação e comunicação dos riscos na cadeia alimentar, sendo o organismo nacional de ligação com as suas entidades congéneres, a nível europeu e internacional. 
  Assim: 
  Nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta o seguinte:  Artigo 1.º Natureza
                            
                           
                             
                               
                             
     1 - A Autoridade de Segurança Alimentar e Económica, abreviadamente designada por ASAE, é um serviço central da administração direta do Estado dotado de autonomia administrativa. 
  2 - A ASAE dispõe das seguintes unidades orgânicas desconcentradas, designadas por unidades regionais: 
  a) Unidade Regional do Norte; 
  b) Unidade Regional do Centro; 
  c) Unidade Regional do Sul.            
         
   
     
                         
   ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                       
  Artigo 2.º Missão e atribuições
                            
                           
                             
                               
                             
     1 - A ASAE tem por missão a fiscalização e prevenção do cumprimento da legislação reguladora do exercício das atividades económicas, nos setores alimentar e não alimentar, bem como a avaliação e comunicação dos riscos na cadeia alimentar, sendo o organismo nacional de ligação com as suas entidades congéneres, a nível europeu e internacional. 
  2 - A ASAE prossegue as seguintes atribuições: 
  a) Na área da fiscalização das atividades económicas: 
  i) Fiscalizar todos os locais onde se proceda a qualquer atividade industrial, designadamente de produtos acabados e ou intermédios, turística, comercial, agrícola, pecuária, de abate, piscatória, incluindo a atividade de pesca lúdica ou qualquer atividade de prestação de serviços, armazéns, escritórios, notários, meios de transporte, entrepostos frigoríficos, empreendimentos turísticos, alojamento local, agências de viagens, empresas de animação turística, campos de férias, casinos e bingos, estabelecimentos de restauração e bebidas, discotecas e bares, cantinas e refeitórios, clínicas médicas e dentárias, clínicas veterinárias, farmácias e armazéns de produtos médico-farmacêuticos, cabeleireiros e centros de estética, recintos de diversão ou de espetáculos, espaços de jogos e recreio, infraestruturas, equipamentos e espaços desportivos, health clubs, portos, gares e aerogares, sem prejuízo das competências atribuídas por lei a outras entidades; 
  ii) Executar, em colaboração com outros organismos competentes, as medidas destinadas a assegurar o abastecimento do País em bens e serviços considerados essenciais, tendo em vista prevenir situações de açambarcamento, desenvolvendo ações de combate à economia paralela e à venda de produtos falsificados ou copiados; 
  iii) Elaborar, executar e divulgar periodicamente o programa de fiscalização do mercado, nos termos do Regulamento (CE) n.º 765/2008, do Parlamento Europeu e do Conselho, de 9 de julho, bem como adotar medidas restritivas de proibição, de restrição da disponibilização, de retirada ou de recolha de produtos no mercado, ao abrigo do mesmo regulamento; 
  iv) Fiscalizar a venda de produtos e serviços nos termos legalmente previstos tendo em vista garantir a segurança e saúde dos consumidores, bem como fiscalizar o cumprimento das obrigações legais dos agentes económicos; 
  v) Desenvolver ações de natureza preventiva e repressiva em matéria de jogo ilícito e apoiar as demais autoridades policiais na prevenção e punição nesta matéria, em articulação com o Serviço de Inspeção de Jogos do Turismo de Portugal, I. P.; 
  vi) Exercer as competências que lhe são cometidas relativamente ao tratamento de reclamações lavradas em livros de reclamações, nos termos em que as mesmas estão previstas no Decreto-Lei n.º 156/2005, de 15 de setembro, alte','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rado pelos Decretos-Leis n.os 371/2007, de 6 de novembro, 118/2009, de 19 de maio, e 317/2009, de 30 de outubro; 
  b) Na área da segurança alimentar: 
  i) Proceder à avaliação dos riscos alimentares e emitir pareceres científicos e técnicos, recomendações e avisos, nomeadamente em matérias relacionadas com a nutrição humana, saúde e bem-estar animal, fitossanidade e organismos geneticamente modificados; 
  ii) Recolher e analisar dados que permitam a caracterização e a avaliação dos riscos que tenham impacte, direto ou indireto, na segurança alimentar, assegurando a comunicação pública e transparente dos riscos e promovendo a divulgação da informação sobre segurança dos alimentos junto dos consumidores, definindo a estratégia da comunicação dos riscos tendo em consideração os conteúdos, os meios e os grupos-alvo da comunicação; 
  iii) Caracterizar e avaliar os riscos que tenham impacte na segurança alimentar, colaborando, na área das suas atribuições, com a Autoridade Europeia para a Segurança dos Alimentos; 
  iv) Acompanhar a participação técnica nacional nas diferentes instâncias internacionais em matéria de segurança alimentar, designadamente quanto às normas e procedimentos de controlo através da presença em reuniões, da elaboração de pareceres e da receção de informações e alertas, integrando o conjunto de entidades a quem são obrigatoriamente comunicadas as mensagens que circulam no sistema de alerta rápido (RASFF); 
  v) Proceder à realização de ensaios laboratoriais de amostras de géneros alimentícios com vista a verificar a sua conformidade legal no âmbito de ações de prevenção e repressão de fraudes, bem como com vista a aferir a autenticidade e genuinidade dos mesmos; 
  vi) Promover ações de natureza preventiva e repressiva em matéria de infrações contra a qualidade, genuinidade, composição, aditivos alimentares e outras substâncias e rotulagem dos géneros alimentícios e dos alimentos para animais, incluindo a realização de perícias e a colheita de amostras no âmbito dos planos nacionais de controlo oficial; 
  vii) Elaborar e coordenar a execução de planos de monitorização ou vigilância relativos ao cumprimento da legislação alimentar das atividades e produtos, nomeadamente efetuando a colheita de amostras nas fases de transporte, armazenamento e comércio por grosso e a retalho, sem prejuízo das suas competências de investigação e fiscalização nas restantes fases da cadeia alimentar, e das competências da Direção-Geral de Alimentação e Veterinária na elaboração e financiamento de planos de colheitas de amostras que decorram das suas atribuições; 
  viii) Fiscalizar os estabelecimentos de abate, preparação, tratamento, armazenamento e venda de produtos de origem animal; 
  ix) Fiscalizar os estabelecimentos que manipulem produtos da pesca, incluindo de aquicultura, navios-fábrica, embarcações, lotas, armazéns e mercados grossistas; 
  x) Fiscalizar a cadeia de comercialização dos produtos de origem vegetal e dos produtos de origem','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' animal, incluindo os produtos da pesca e da aquicultura e atividades conexas; 
  xi) Fiscalizar a circulação e comércio de uvas destinadas à produção de vinho, de mosto e de vinho e produtos vínicos; 
  xii) Fiscalizar os lagares de azeite, bem como o destino do azeite obtido da azeitona laborada e seus subprodutos; 
  c) Na área da cooperação interna e externa: 
  i) Promover a criação de uma rede de intercâmbio de informação entre entidades que trabalhem nos domínios das suas competências; 
  ii) Promover e colaborar na divulgação da legislação sobre o exercício dos diferentes setores da economia cuja fiscalização lhe esteja atribuída, designadamente junto dos municípios e associações de municípios, das associações de consumidores, associações empresariais, associações agrícolas e das pescas e organizações sindicais; 
  iii) Exercer as funções de autoridade coordenadora e ponto de contacto nacional no âmbito do sistema geral de informação de apoio (Sistema ICSMS), conforme o artigo 23.º do Regulamento (CE) n.º 765/2008, do Parlamento Europeu e do Conselho, de 9 de julho, bem como colaborar, direta e indiretamente, na troca de informação sobre produtos colocados ou disponibilizados no mercado que apresentam um risco grave, através do Sistema RAPEX; 
  d) Na área da instrução e aplicação de sanções em processos de contraordenação: 
  i) Proceder à investigação e instrução de processos por contraordenação cuja competência lhe esteja legalmente atribuída, bem como arquivá-los sempre que se verificar que os factos que constam dos autos não constituem infração ou não existam elementos de prova suscetíveis de imputar a prática da infração a um determinado agente; 
  e) Nas áreas da divulgação e informação e da valorização profissional: 
  i) Promover a divulgação dos resultados da atividade operacional de inspeção, fiscalização e investigação, sem prejuízo das regras inerentes ao segredo de justiça; 
  ii) Desenvolver e executar formação técnica e geral, bem como conceber e organizar ações de formação externas. 
  3 - A ASAE, enquanto autoridade nacional de fiscalização das atividades económicas, exerce a sua atividade em todo o território do continente. 
  4 - No âmbito da fiscalização das atribuições das subalíneas v) da alínea a) e xi) da alínea b) do n.º 2, a ASAE exerce a sua atividade em todo o território nacional. 
  5 - Enquanto entidade nacional responsável pela avaliação e comunicação dos riscos na cadeia alimentar e, no âmbito do controlo oficial dos géneros alimentícios, a ASAE exerce a sua atividade em todo o território nacional.            
         
   
     
                         
                          
  Artigo 3.º Órgãos
                            
                           
                             
                               
                             
     1 - A ASAE é dirigida por um inspetor-geral, coadjuvado por dois subinspetores-gerais, cargos de direção superior dos 1.º e 2.º graus, respetivamente. 
  2 ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('- É ainda órgão da ASAE o conselho científico.            
         
   
     
                         
                          
  Artigo 4.º Inspetor-geral
                            
                           
                             
                               
                             
     1 - Sem prejuízo das competências que lhe forem conferidas por lei ou que nele sejam delegadas ou subdelegadas, compete ao inspetor-geral: 
  a) Aprovar as recomendações e avisos que vinculam a ASAE na área dos riscos da cadeia alimentar, mediante parecer, quando aplicável, do dirigente superior responsável por essa área; 
  b) Propor ao membro do Governo responsável pela área da economia a designação dos membros do conselho científico; 
  c) Participar nas reuniões do conselho científico, sempre que entender; 
  d) Aplicar coimas e sanções acessórias em matéria económica. 
  2 - Os subinspetores-gerais exercem as competências que lhes sejam delegadas ou subdelegadas pelo inspetor-geral, devendo este identificar a quem compete substituí-lo nas suas faltas e impedimentos.            
         
   
     
                         
                          
  Artigo 5.º Área dos riscos na cadeia alimentar
                            
                           
                             
                               
                             
     Compete ao dirigente superior responsável pela área dos riscos na cadeia alimentar: 
  a) Dirigir, coordenar e orientar a área de riscos alimentares e respetivos laboratórios; 
  b) Emitir parecer sobre as recomendações e avisos que vinculam a ASAE e sobre as iniciativas propostas pelo conselho científico; 
  c) Assegurar a necessária articulação com os organismos congéneres dos países da União Europeia, assegurando a representação da ASAE sempre que indicado pelo inspetor-geral, quando aplicável; 
  d) Propor ao inspetor-geral a designação dos membros do conselho científico, quando aplicável; 
  e) Avaliar e aprovar as iniciativas que lhe são propostas pelo conselho científico, designadamente a criação e a composição de painéis temáticos; 
  f) Divulgar, após autorização, os pareceres do conselho científico; 
  g) Proceder aos contactos respeitantes à comunicação de riscos com os órgãos de comunicação, nos termos a articular com o inspetor-geral.            
         
   
     
                         
                          
  Artigo 6.º Conselho científico
                            
                           
                             
                               
                             
     1 - O conselho científico é o órgão de consulta especializada e de acompanhamento da área dos riscos da cadeia alimentar, na dependência do dirigente superior responsável por esta área, em matérias científicas, de desenvolvimento tecnológico e de projetos de investigação, gozando de plena autonomia técnico-científica para o efeito. 
  2 - O conselho científico é composto por entr','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e três a seis personalidades de reconhecido mérito científico, designados pelo membro do Governo responsável pela área da economia, sob proposta do inspetor-geral, preferencialmente de entre professores universitários e investigadores de diversas especialidades, incluindo a comunicação de riscos. 
  3 - Ao conselho científico compete: 
  a) Emitir pareceres científicos, a solicitação do dirigente superior responsável pela área dos riscos da cadeia alimentar, ou, mediante aprovação deste, por sua própria iniciativa, ou a solicitação de entidades responsáveis por interesses relevantes na área da segurança alimentar, incluindo, para além dos organismos e serviços públicos com competências no setor alimentar, as associações mais representativas de consumidores, produtores, industriais e comerciantes; 
  b) Proceder à coordenação geral necessária para garantir a coerência do procedimento de formulação de pareceres científicos, em particular no que respeita à adoção de regras de funcionamento e à harmonização dos métodos de trabalho; 
  c) Acompanhar o progresso científico e técnico na área da segurança alimentar; 
  d) Proceder, entre outras atividades, à avaliação dos riscos na cadeia alimentar e propor as medidas legislativas e administrativas adequadas; 
  e) Propor ao dirigente superior responsável pela área dos riscos da cadeia alimentar a realização de estudos, conferências, colóquios, seminários e outras atividades destinadas a avaliar, aprofundar e divulgar o conhecimento da segurança alimentar; 
  f) Propor ao dirigente superior responsável pela área dos riscos da cadeia alimentar a criação e composição dos painéis temáticos; 
  g) Elaborar o projeto de regulamento interno e submetê-lo ao dirigente superior responsável pela área dos riscos da cadeia alimentar. 
  4 - O conselho científico elege, de entre os membros a que alude o n.º 2, o respetivo presidente, por voto secreto e com maioria de dois terços, e delibera sobre a sua organização e funcionamento. 
  5 - Para efeitos da comunicação de riscos, o conselho científico está inibido de proceder à comunicação dos riscos, bem como a qualquer outra manifestação ou declaração relacionada com as competências deste órgão, sempre que não tenha obtido prévia e expressa autorização do inspetor-geral da ASAE. 
  6 - Os membros do conselho científico, salvo aqueles que são trabalhadores da ASAE, têm direito ao abono de senhas de presença, nos termos a definir por despacho dos membros do Governo responsáveis pelas áreas das finanças e da economia.            
         
   
     
                         
                          
  Artigo 7.º Painéis temáticos
                            
                           
                             
                               
                             
     1 - Podem ser criados pelo inspetor-geral, sob proposta do conselho científico, painéis temáticos com a finalidade de prestar apoio especializado a este órgão na elaboração de pareceres cientí','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ficos e avaliação de riscos na cadeia alimentar. 
  2 - Podem existir até um máximo de seis painéis temáticos em simultâneo, podendo estes ser constituídos por um máximo de cinco personalidades com qualificação e experiência nas respetivas áreas. 
  3 - As regras de funcionamento dos painéis temáticos são fixadas em regulamento, aprovado pelo inspetor-geral, sob proposta do conselho científico, ouvido o dirigente superior responsável pela área dos riscos da cadeia alimentar. 
  4 - Os membros dos painéis temáticos, salvo aqueles que são trabalhadores da ASAE, têm direito ao abono de senhas de presença, nos termos a definir por despacho dos membros do Governo responsáveis pelas áreas das finanças e da economia.            
         
   
     
                         
                          
  Artigo 8.º Tipo de organização interna
                            
                           
                             
                               
                             
     A organização interna da ASAE obedece ao seguinte modelo estrutural misto: 
  a) Nas áreas de atividade de avaliação e comunicação do risco, laboratorial, serviços administrativos, técnicos e apoio jurídico, o modelo de estrutura hierarquizada; 
  b) Nas áreas de atividade de fiscalização, investigação e técnico-pericial, planeamento operacional e de instrução processual e contraordenações, o modelo de estrutura matricial.            
         
   
     
                         
                          
  Artigo 9.º Receitas
                            
                           
                             
                               
                             
     1 - A ASAE dispõe das receitas provenientes de dotações que lhe forem atribuídas no Orçamento do Estado. 
  2 - A ASAE dispõe ainda das seguintes receitas próprias: 
  a) As quantias cobradas pela prestação de serviços no âmbito das suas atribuições; 
  b) O produto da venda de publicações e trabalhos editados pela ASAE; 
  c) O produto das coimas que lhe esteja consignado; 
  d) O produto da cobrança das taxas relativas às bebidas vínicas e não vínicas; 
  e) As verbas provenientes de transferências anuais efetuadas pelo Turismo de Portugal, I. P., e consignadas à atuação da ASAE na prossecução das ações de natureza preventiva e repressiva de práticas ilícitas em matéria de jogos de fortuna e azar, em articulação com o Serviço de Inspeção de Jogos do Turismo de Portugal, I. P.; 
  f) Os subsídios, subvenções, comparticipações, doações e legados de entidades públicas e privadas; 
  g) Quaisquer outras receitas que por lei, contrato ou outro título, lhe sejam atribuídas. 
  3 - As quantias cobradas pela ASAE são fixadas e periodicamente atualizadas por despacho dos membros do Governo responsáveis pelas áreas das finanças e da economia, tendo em atenção os meios humanos e materiais mobilizados em cada caso, podendo ainda ser tidos em conta os custos indiretos de funcionamento.            
    ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
   
     
                         
                          
  Artigo 10.º Despesas
                            
                           
                             
                               
                             
     Constituem despesas da ASAE as que resultem de encargos decorrentes da prossecução das atribuições que lhe estão cometidas.            
         
   
     
                         
                          
  Artigo 11.º Mapa de cargos de direção
                            
                           
                             
                               
                             
     Os lugares de direção superior dos 1.º e 2.º graus e de direção intermédia do 1.º grau constam do mapa anexo ao presente decreto-lei, do qual faz parte integrante.            
         
   
     
                         
                          
  Artigo 12.º Estatuto remuneratório dos chefes de equipas multidisciplinares
                            
                           
                             
                               
                             
     Aos chefes de equipa multidisciplinar é atribuído um acréscimo remuneratório correspondente a (euro) 188,80, até ao limite do estatuto remuneratório fixado para os chefes de divisão, quando: 
  a) Nas áreas de atividade de fiscalização e investigação, dirijam no mínimo seis inspetores; 
  b) Nas áreas de atividade técnico-pericial, planeamento operacional e de instrução processual e contraordenações, dirijam no mínimo seis trabalhadores.            
         
   
     
                         
                          
  Artigo 13.º Cooperação com outras entidades
                            
                           
                             
                               
                             
     1 - A ASAE e todas as entidades com funções de prevenção e investigação criminal mantêm mútua cooperação no exercício das respetivas atribuições. 
  2 - Para cumprimento das atribuições da ASAE, as entidades públicas e privadas, nas pessoas dos respetivos representantes, prestam toda a colaboração que lhes for solicitada. 
  3 - A ASAE colabora com as autoridades judiciárias, nos termos do disposto no Código de Processo Penal, procedendo à investigação dos crimes cuja competência lhe esteja especificamente atribuída por lei. 
  4 - A ASAE pode estabelecer relações de cooperação com organismos similares de outros países ou com organizações internacionais, em articulação com os serviços e órgãos competentes do Ministério dos Negócios Estrangeiros.            
         
   
     
                         
                          
  Artigo 14.º Livre-trânsito
                            
                           
                             
                               
                             
     Os trabalhadores da ASAE que desempenhem funções de segurança de pessoas, instalações e equipamentos, nomeadamente que ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('apoiem a investigação criminal no transporte e guarda de detidos, de material apreendido e de valores, e que conduzam viaturas operacionais, têm direito a cartão de identificação profissional e de livre-trânsito, à semelhança do pessoal de inspeção.            
         
   
     
                         
                          
  Artigo 15.º Órgão de polícia criminal
                            
                           
                             
                               
                             
     1 - A ASAE detém poderes de autoridade e é órgão de polícia criminal. 
  2 - São autoridades de polícia criminal, nos termos e para os efeitos no Código de Processo Penal: 
  a) O inspetor-geral; 
  b) Os subinspetores -gerais; 
  c) Os inspetores-diretores; 
  d) Os inspetores-chefes; 
  e) Os chefes de equipas multidisciplinares.            
         
   
     
                         
                          
  Artigo 16.º Uso e porte de arma
                            
                           
                             
                               
                             
     Os trabalhadores de inspeção e os dirigentes dos serviços de inspeção têm direito a possuir e a usar armas de todas as classes previstas na Lei n.º 5/2006, de 23 de fevereiro, com exceção da classe A, distribuídas pelo Estado, com dispensa da respetiva licença de uso e porte de arma, valendo como tal o respetivo cartão de identificação profissional.            
         
   
     
                         
                          
  Artigo 17.º Sucessão
                            
                           
                             
                               
                             
     A ASAE sucede nas atribuições da Comissão de Aplicação de Coimas em Matéria Económica e de Publicidade no domínio da economia.            
         
   
     
                         
                          
  Artigo 18.º Critérios de seleção de pessoal
                            
                           
                             
                               
                             
     É critério geral e abstrato de seleção do pessoal necessário à prossecução das atribuições da ASAE o desempenho de funções na Comissão de Aplicação de Coimas em Matéria Económica e de Publicidade no domínio da economia.            
         
   
     
                         
                          
  Artigo 19.º Norma revogatória
                            
                           
                             
                               
                             
     São revogados: 
  a) O  Decreto-Lei nº 274/2007, de 30 de julho; 
  b) O  Decreto-Lei nº 143/2007, de 27 de abril.            
         
   
     
                         
                          
  Artigo 20.º Entrada em vigor
                            
                           
                             
                             ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  
                             
     O presente decreto-lei entra em vigor no 1.º dia do mês seguinte ao da sua publicação. 
  
  Visto e aprovado em Conselho de Ministros de 28 de junho de 2012. - Pedro Passos Coelho - Luís Filipe Bruno da Costa de Morais Sarmento - Miguel Bento Martins Costa Macedo e Silva - António Joaquim Almeida Henriques - Maria de Assunção Oliveira Cristas Machado da Graça. 
  Promulgado em 9 de agosto de 2012. 
  Publique-se. 
  O Presidente da República, Aníbal Cavaco Silva. 
  Referendado em 14 de agosto de 2012. 
  Pelo Primeiro-Ministro, Vítor Louçã Rabaça Gaspar, Ministro de Estado e das Finanças.            
         
   
     
                         
                          
  ANEXO
                            
                           
                             
                               
                             
     (a que se refere o artigo 11.º) 
  Mapa de pessoal dirigente','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:55  
    
  Lei n.º 63/2007, de 06 de Novembro  (versão actualizada) LEI ORGÂNICA DA GNR    
    
 
Contém as seguintes alterações:   - Rectif. n.º 1-A/2008, de 04 de Janeiro   - Lei n.º 73/2021, de 12 de Novembro   - Lei n.º 53/2023, de 31 de Agosto  
                         
                          
SUMÁRIOAprova a orgânica da Guarda Nacional Republicana
A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:TÍTULO I Disposições gerais CAPÍTULO I Natureza, atribuições e símbolos  Artigo 1.º Definição
                            
                           
                             
                               
                             
     1 - A Guarda Nacional Republicana, adiante designada por Guarda, é uma força de segurança de natureza militar, constituída por militares organizados num corpo especial de tropas e dotada de autonomia administrativa. 
  2 - A Guarda tem por missão, no âmbito dos sistemas nacionais de segurança e protecção, assegurar a legalidade democrática, garantir a segurança interna e os direitos dos cidadãos, bem como colaborar na execução da política de defesa nacional, nos termos da Constituição e da lei.            
         
   
     
                         
                          
  Artigo 2.º Dependência
                            
                           
                             
                               
                             
     1 - A Guarda depende do membro do Governo responsável pela área da administração interna. 
  2 - As forças da Guarda são colocadas na dependência operacional do Chefe do Estado-Maior-General das Forças Armadas, através do seu comandante-geral, nos casos e termos previstos nas Leis de Defesa Nacional e das Forças Armadas e do regime do estado de sítio e do estado de emergência, dependendo, nesta medida, do membro do Governo responsável pela área da defesa nacional no que respeita à uniformização, normalização da doutrina militar, do armamento e do equipamento.            
         
   
     
                         
                          
  Artigo 3.º 
Atribuições
                            
                           
                             
                               
                             
     1 - Constituem atribuições da Guarda:
  a) Garantir as condições de segurança que permitam o exercício dos direitos e liberdades e o respeito pelas garantias dos cidadãos, bem como o pleno funcionamento das instituições democráticas, no respeito pela legalidade e pelos princípios do Estado de direito;
  b) Garantir a ordem e a tranquilidade públicas e a segurança e a protecção das pessoas e dos bens;
  c) Prevenir a criminalidade em geral, em coordenação com as demais forças e serviços de segurança;
  d) Prevenir a prática dos demais actos contrários à lei e aos regulamentos;
  e) Desenvolver as acções de investigação criminal e contra-ordenacional que lhe sejam atribuí','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('das por lei, delegadas pelas autoridades judiciárias ou solicitadas pelas autoridades administrativas;
  f) Velar pelo cumprimento das leis e regulamentos relativos à viação terrestre e aos transportes rodoviários, e promover e garantir a segurança rodoviária, designadamente, através da fiscalização, do ordenamento e da disciplina do trânsito;
  g) Garantir a execução dos actos administrativos emanados da autoridade competente que visem impedir o incumprimento da lei ou a sua violação continuada;
  h) Participar no controlo da entrada e saída de pessoas e bens no território nacional;
  i) Proteger, socorrer e auxiliar os cidadãos e defender e preservar os bens que se encontrem em situações de perigo, por causas provenientes da acção humana ou da natureza;
  j) Manter a vigilância e a protecção de pontos sensíveis, nomeadamente infra-estruturas rodoviárias, ferroviárias, aeroportuárias e portuárias, edifícios públicos e outras instalações críticas;
  l) Garantir a segurança nos espectáculos, incluindo os desportivos, e noutras actividades de recreação e lazer, nos termos da lei;
  m) Prevenir e detectar situações de tráfico e consumo de estupefacientes ou outras substâncias proibidas, através da vigilância e do patrulhamento das zonas referenciadas como locais de tráfico ou de consumo;
  n) Participar na fiscalização do uso e transporte de armas, munições e substâncias explosivas e equiparadas que não pertençam às demais forças e serviços de segurança ou às Forças Armadas, sem prejuízo das competências atribuídas a outras entidades;
  o) Participar, nos termos da lei e dos compromissos decorrentes de acordos, tratados e convenções internacionais, na execução da política externa, designadamente em operações internacionais de gestão civil de crises, de paz e humanitárias, no âmbito policial e de protecção civil, bem como em missões de cooperação policial internacional e no âmbito da União Europeia e na representação do País em organismos e instituições internacionais;
  p) Contribuir para a formação e informação em matéria de segurança dos cidadãos;
  q) Vigiar, fiscalizar e controlar as fronteiras marítimas, incluindo os terminais de cruzeiro, e as fronteiras terrestres, assim como a circulação de pessoas nos postos de fronteira autorizados;
  r) Atribuir vistos na fronteira, nos termos da lei, nas áreas da sua jurisdição;
  s) A execução do cumprimento das decisões prévias da entidade competente de afastamento coercivo e das decisões judiciais de expulsão de cidadãos estrangeiros a concretizar por via terrestre e marítima;
  t) Assegurar a execução de processos de readmissão, a concretizar por via terrestre e marítima;
  u) Assegurar a realização de controlos móveis e de operações conjuntas com serviços ou forças de segurança congéneres, nacionais ou estrangeiros, nas suas áreas de jurisdição;
  v) Gerir os centros de instalação temporária e os espaços equiparados nas suas áreas de jurisdição;
  x) Prosseguir as demais atribuições que lhe forem co','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('metidas por lei.
  2 - Constituem, ainda, atribuições da Guarda:
  a) Assegurar o cumprimento das disposições legais e regulamentares referentes à protecção e conservação da natureza e do ambiente, bem como prevenir e investigar os respectivos ilícitos;
  b) Garantir a fiscalização, o ordenamento e a disciplina do trânsito em todas as infra-estruturas constitutivas dos eixos da Rede Nacional Fundamental e da Rede Nacional Complementar, em toda a sua extensão, fora das áreas metropolitanas de Lisboa e Porto;
  c) Assegurar, no âmbito da sua missão própria, a vigilância, patrulhamento e intercepção terrestre e marítima, em toda a costa e mar territorial do continente e das Regiões Autónomas;
  d) Prevenir e investigar as infracções tributárias, fiscais e aduaneiras, bem como fiscalizar e controlar a circulação de mercadorias sujeitas à acção tributária, fiscal ou aduaneira;
  e) Controlar e fiscalizar as embarcações, seus passageiros e carga, para os efeitos previstos na alínea anterior e, supletivamente, para o cumprimento de outras obrigações legais;
  f) Participar na fiscalização das actividades de captura, desembarque, cultura e comercialização das espécies marinhas, em articulação com a Autoridade Marítima Nacional e no âmbito da legislação aplicável ao exercício da pesca marítima e cultura das espécies marinhas;
  g) Executar acções de prevenção e de intervenção de primeira linha, em todo o território nacional, em situação de emergência de protecção e socorro, designadamente nas ocorrências de incêndios florestais ou de matérias perigosas, catástrofes e acidentes graves;
  h) Colaborar na prestação das honras de Estado;
  i) Cumprir, no âmbito da execução da política de defesa nacional e em cooperação com as Forças Armadas, as missões militares que lhe forem cometidas;
  j) Assegurar o ponto de contacto nacional para intercâmbio internacional de informações relativas aos fenómenos de criminalidade automóvel com repercussões transfronteiriças, sem prejuízo das competências atribuídas a outros órgãos de polícia criminal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Rectif. n.º 1-A/2008, de 04 de Janeiro   - Lei n.º 73/2021, de 12 de Novembro   - Lei n.º 53/2023, de 31 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 63/2007, de 06 de Novembro    - 2ª versão: Rectif. n.º 1-A/2008, de 04 de Janeiro    - 3ª versão: Lei n.º 73/2021, de 12 de Novembro   
     
                         
                          
  Artigo 4.º Conflitos de natureza privada
                            
                           
                             
                               
                             
     A Guarda não pode dirimir conflitos de natureza privada, devendo, nesses casos, limitar a sua acção à manutenção da ordem pública.            
         
   
     
                         
                          
  Artigo 5.º Âmbito territorial
                            
         ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                  
                             
                               
                             
     1 - As atribuições da Guarda são prosseguidas em todo o território nacional e no mar territorial. 
  2 - No caso de atribuições cometidas simultaneamente à Polícia de Segurança Pública, a área de responsabilidade da Guarda é definida por portaria do ministro da tutela. 
  3 - Fora da área de responsabilidade definida nos termos do número anterior, a intervenção da Guarda depende: 
  a) Do pedido de outra força de segurança; 
  b) De ordem especial; 
  c) De imposição legal. 
  4 - A atribuição prevista na alínea d) do n.º 2 do artigo 3.º pode ser prosseguida na zona contígua. 
  5 - A Guarda pode prosseguir a sua missão fora do território nacional, desde que legalmente mandatada para esse efeito.            
         
   
     
                         
                          
  Artigo 6.º Deveres de colaboração
                            
                           
                             
                               
                             
     1 - A Guarda, sem prejuízo das prioridades legais da sua actuação, coopera com as demais forças e serviços de segurança, bem como com as autoridades públicas, designadamente com os órgãos autárquicos e outros organismos, nos termos da lei. 
  2 - As autoridades da administração central, regional e local, os serviços públicos e demais entidades públicas e privadas devem prestar à Guarda a colaboração que legitimamente lhes for solicitada para o exercício das suas funções. 
  3 - As autoridades administrativas devem comunicar à Guarda, quando solicitado, o teor das decisões sobre as infracções que esta lhes tenha participado.            
         
   
     
                         
                          
  Artigo 7.º Estandarte nacional
                            
                           
                             
                               
                             
     A Guarda e as suas unidades, incluindo as unidades constituídas para actuar fora do território nacional e o estabelecimento de ensino, têm direito ao uso do estandarte nacional.            
         
   
     
                         
                          
  Artigo 8.º Símbolos
                            
                           
                             
                               
                             
     1 - A Guarda tem direito a brasão de armas, bandeira heráldica, hino, marcha, selo branco e condecoração privativa. 
  2 - As unidades da Guarda têm direito a brasão de armas, selo branco e bandeiras heráldicas, que, nas suas subunidades, tomarão as formas de guião de mérito. 
  3 - O comandante-geral tem direito ao uso de galhardete. 
  4 - Os símbolos e a condecoração previstos nos números anteriores, bem como o regulamento de atribuição desta, são aprovados por portaria do ministro da tutela.            
         
   
     
                         
 ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                         
  Artigo 9.º Datas comemorativas
                            
                           
                             
                               
                             
     1 - O Dia da Guarda é comemorado a 3 de Maio, em evocação da lei que criou a actual instituição nacional, em 1911. 
  2 - As unidades da Guarda têm direito a um dia festivo para a consagração da respectiva memória histórica, definido por despacho do comandante-geral.            
         
   
     
                         
                          
CAPÍTULO II 
  Autoridades e órgãos de polícia  Artigo 10.º Comandantes e agentes de força pública
                            
                           
                             
                               
                             
     1 - Os militares da Guarda no exercício do comando de forças têm a categoria de comandantes de força pública. 
  2 - Considera-se força pública, para efeitos do número anterior, o efectivo mínimo de dois militares em missão de serviço. 
  3 - Os militares da Guarda são considerados agentes da força pública e de autoridade quando lhes não deva ser atribuída qualidade superior.            
         
   
     
                         
                          
  Artigo 11.º Autoridades de polícia
                            
                           
                             
                               
                             
     1 - São consideradas autoridades de polícia: 
  a) O comandante-geral; 
  b) O 2.º comandante-geral; 
  c) O comandante do Comando Operacional da Guarda; 
  d) Os comandantes de unidade e subunidades de comando de oficial; 
  e) Outros oficiais da Guarda, quando no exercício de funções de comando ou chefia operacional. 
  2 - Compete às autoridades de polícia referidas no número anterior determinar a aplicação das medidas de polícia previstas na lei.            
         
   
     
                         
                          
  Artigo 12.º Autoridades e órgãos de polícia criminal
                            
                           
                             
                               
                             
     1 - Para efeitos do Código de Processo Penal, consideram-se: 
  a) Autoridades de polícia criminal as entidades referidas no n.º 1 do artigo anterior; 
  b) Órgãos de polícia criminal os militares da Guarda incumbidos de realizar quaisquer actos ordenados por autoridade judiciária ou determinados por aquele Código. 
  2 - Enquanto órgãos de polícia criminal e sem prejuízo da organização hierárquica da Guarda, os militares da Guarda actuam sob a direcção e na dependência funcional da autoridade judiciária competente. 
  3 - Os actos determinados pelas autoridades judiciárias são realizados pelos serviços e militares para esse efeito designados pela respectiva cadeia de comando, no âmbito da sua autonomia técnica e táctica.            
         
   
     
             ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('            
                          
  Artigo 13.º Autoridade de polícia tributária
                            
                           
                             
                               
                             
     1 - Para efeitos do regime jurídico aplicável às infracções tributárias, são consideradas autoridades de polícia tributária: 
  a) Todos os oficiais no exercício de funções de comando nas Unidades de Controlo Costeiro e de Acção Fiscal e nas respectivas subunidades; 
  b) Outros oficiais da Guarda, quando no exercício de funções de comando operacional de âmbito tributário. 
  2 - De forma a permitir o cumprimento da sua missão tributária, bem como a prossecução das suas atribuições de natureza financeira e patrimonial, a Guarda mantém uma ligação funcional com o Ministério das Finanças, regulada por portaria conjunta do ministro da tutela e do membro do Governo responsável pela área das finanças.            
         
   
     
                         
                          
  Artigo 14.º Medidas de polícia e meios de coerção
                            
                           
                             
                               
                             
     1 - No âmbito das suas atribuições, a Guarda utiliza as medidas de polícia legalmente previstas e nas condições e termos da Constituição e da lei de segurança interna, não podendo impor restrições ou fazer uso dos meios de coerção para além do estritamente necessário. 
  2 - Quem faltar à obediência devida a ordem ou a mandado legítimos, regularmente comunicados e emanados de autoridade de polícia ou agente de autoridade da Guarda, é punido com a pena legalmente prevista para a desobediência qualificada.            
         
   
     
                         
                          
CAPÍTULO III 
  Requisição de forças e prestação de serviços  Artigo 15.º Requisição de forças
                            
                           
                             
                               
                             
     1 - As autoridades judiciárias e administrativas podem requisitar à Guarda a actuação de forças para a manutenção da ordem e tranquilidade públicas. 
  2 - A requisição de forças é apresentada junto da autoridade de polícia territorialmente competente, indicando a natureza do serviço a desempenhar e o motivo ou a ordem que as justifica. 
  3 - As forças requisitadas actuam no quadro das suas competências e de forma a cumprirem a sua missão, mantendo total subordinação aos comandos de que dependem.            
         
   
     
                         
                          
  Artigo 16.º Prestação de serviços especiais
                            
                           
                             
                               
                             
     1 - A Guarda pode manter pessoal militar em organismos de interesse público, em condições definidas por portaria do ministro da tu','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tela. 
  2 - Os militares da Guarda podem ser nomeados em comissão de serviço para organismos internacionais ou países estrangeiros, em função dos interesses nacionais e dos compromissos assumidos no âmbito da cooperação internacional, nos termos legalmente estabelecidos. 
  3 - O pessoal referido no n.º 1 cumpre, para efeitos de ordem pública, as directivas do comando com jurisdição na respectiva área. 
  4 - A Guarda pode ainda prestar serviços especiais, mediante solicitação, que, após serem autorizados pela entidade competente, são remunerados pelos respectivos requisitantes nos termos que forem regulamentados.            
         
   
     
                         
                          
  Artigo 17.º Prestação de serviços a outros organismos públicos
                            
                           
                             
                               
                             
     1 - Sem prejuízo da missão que lhe está cometida e no âmbito do dever de coadjuvação dos tribunais, a Guarda pode afectar pessoal militar para a realização das actividades de comunicação dos actos processuais previstos no Código de Processo Penal. 
  2 - A Guarda pode ainda afectar pessoal militar para prestar serviço a órgãos e entidades da administração central, regional e local. 
  3 - A prestação e o pagamento das acções previstas nos números anteriores, quando não regulados em lei especial, são objecto de portaria conjunta dos membros do Governo responsáveis pelas áreas da administração interna e das finanças e pela tutela da entidade requisitante.            
         
   
     
                         
                          
  Artigo 18.º Colaboração com entidades públicas e privadas
                            
                           
                             
                               
                             
     1 - Sem prejuízo do cumprimento da sua missão, a Guarda pode prestar colaboração a outras entidades públicas ou privadas que a solicitem, para garantir a segurança de pessoas e bens ou para a prestação de outros serviços, mediante pedidos concretos que lhe sejam formulados, os quais serão sujeitos a decisão caso a caso. 
  2 - A administração central pode estabelecer protocolos com as autarquias locais para a execução das responsabilidades de construção, aquisição ou beneficiação de instalações e edifícios para a Guarda sempre que as razões de oportunidade e conveniência o aconselhem. 
  3 - O pagamento dos serviços efectuados pela Guarda ao abrigo do n.º 1 é regulado na portaria referida no n.º 3 do artigo anterior.            
         
   
     
                         
                          
TÍTULO IIOrganização geralCAPÍTULO IDisposições gerais   Artigo 19.º Categorias profissionais e postos
                            
                           
                             
                               
                             
     1 - A Guarda está organizada hierarquicamen','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('te e os militares dos seus quadros permanentes estão sujeitos à condição militar, nos termos da lei de bases gerais do Estatuto da Condição Militar. 
  2 - Os militares da Guarda agrupam-se hierarquicamente nas seguintes categorias profissionais, subcategorias e postos: 
  a) Categoria profissional de oficiais: 
  i) Oficiais generais, que compreende os postos de tenente-general e major-general; 
  ii) Oficiais superiores, que compreende os postos de coronel, tenente-coronel e major; 
  iii) Capitães, que compreende o posto de capitão; 
  iv) Oficiais subalternos, que compreende os postos de tenente e alferes; 
  b) Categoria profissional de sargentos, que compreende os postos de sargento-mor, sargento-chefe, sargento-ajudante, primeiro-sargento, segundo-sargento e furriel; 
  c) Categoria profissional de guardas, que compreende os postos de cabo-mor, cabo-chefe, cabo, guarda principal e guarda. 
  3 - As promoções a oficial general realizam-se por escolha de entre os oficiais com formação de nível superior e qualificações complementares idênticas às exigidas para acesso aos postos de contra-almirante ou de major-general das Forças Armadas. 
  4 - As promoções a oficial general, bem como as promoções de oficiais generais, do quadro de pessoal da Guarda, são sujeitas a aprovação pelo Ministro da Administração Interna e a confirmação pelo Presidente da República, sem o que não produzem efeitos. 
  5 - Os postos da subcategoria de oficiais generais são constituídos pelo número máximo de 11 efectivos.            
         
   
     
                         
                          
  Artigo 20.º Estrutura geral
                            
                           
                             
                               
                             
     A Guarda compreende: 
  a) A estrutura de comando; 
  b) As unidades; 
  c) O estabelecimento de ensino.            
         
   
     
                         
                          
  Artigo 21.º Estrutura de comando
                            
                           
                             
                               
                             
     1 - A estrutura de comando compreende: 
  a) O Comando da Guarda; 
  b) Os órgãos superiores de comando e direcção. 
  2 - O Comando da Guarda compreende: 
  a) O comandante-geral; 
  b) O 2.º comandante-geral; 
  c) O órgão de inspecção; 
  d) Os órgãos de conselho; 
  e) A Secretaria-Geral. 
  3 - São órgãos superiores de comando e direcção: 
  a) O Comando Operacional (CO); 
  b) O Comando da Administração dos Recursos Internos (CARI); 
  c) O Comando da Doutrina e Formação (CDF).            
         
   
     
                         
                          
  Artigo 22.º 
Unidades e estabelecimento de ensino
                            
                           
                             
                               
                             
     1 - Na Guarda existem as seguintes unidades:
  a)','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' O Comando-Geral;
  b) Territoriais, os comandos territoriais;
  c) Especializadas, a Unidade de Controlo Costeiro e de Fronteiras (UCCF), a Unidade de Ação Fiscal (UAF) e a Unidade Nacional de Trânsito (UNT);
  d) De representação, a Unidade de Segurança e Honras de Estado (USHE);
  e) De intervenção e reserva, a Unidade de Intervenção (UI).
  2 - Podem ser constituídas unidades para actuar fora do território nacional, nos termos da lei.
  3 - O estabelecimento de ensino da Guarda é a Escola da Guarda (EG).            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 73/2021, de 12 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 63/2007, de 06 de Novembro   
     
                         
                          
CAPÍTULO II 
  Estrutura de comando 
  SECÇÃO I 
  Comando da Guarda  Artigo 23.º Comandante-geral
                            
                           
                             
                               
                             
     1 - O comandante-geral é um tenente-general nomeado por despacho conjunto do Primeiro-Ministro, do ministro da tutela e do membro do Governo responsável pela área da defesa nacional, ouvido o Conselho de Chefes de Estado-Maior se a nomeação recair em oficial general das Forças Armadas. 
  2 - O comandante-geral é o responsável pelo cumprimento das missões gerais da Guarda, bem como de outras que lhe sejam cometidas por lei. 
  3 - Além das competências próprias dos cargos de direcção superior de 1.º grau, compete ao comandante-geral: 
  a) Exercer o comando completo sobre todas as forças e elementos da Guarda; 
  b) Representar a Guarda; 
  c) Exercer o poder disciplinar; 
  d) Atribuir a condecoração prevista no artigo 8.º; 
  e) Propor ao ministro da tutela a requisição ao membro do Governo responsável pela área da defesa nacional do pessoal dos ramos das Forças Armadas necessários à Guarda; 
  f) Mandar executar as operações de recrutamento do pessoal necessário aos quadros da Guarda; 
  g) Decidir e mandar executar toda a actividade respeitante à organização, meios e dispositivos, operações, instrução, serviços técnicos, financeiros, logísticos e administrativos da Guarda; 
  h) Dirigir a administração financeira da Guarda, de acordo com as competências legais que lhe são conferidas; 
  i) Firmar contratos para aquisição de bens e serviços dentro da sua competência e das autorizações que lhe forem conferidas; 
  j) Relacionar-se com os comandantes superiores das Forças Armadas, comandantes e directores-gerais das restantes forças e serviços de segurança e das demais entidades públicas e privadas; 
  l) Aplicar coimas; 
  m) Inspeccionar ou mandar inspeccionar as unidades, órgãos e serviços da Guarda; 
  n) Presidir ao Conselho Superior da Guarda e ao Conselho de Ética, Deontologia e Disciplina; 
  o) Homologar as decisões da Junta Superior de Saúde; 
  p) Autorizar o desempenho pela Guarda de serviços de carácter especial, a','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' pedido de outras entidades; 
  q) Exercer as demais competências que lhe sejam delegadas ou cometidas por lei. 
  4 - O comandante-geral pode delegar as suas competências próprias no 2.º comandante-geral e nos titulares dos órgãos que lhe estão directamente subordinados.            
         
   
     
                         
                          
  Artigo 24.º Gabinete do comandante-geral
                            
                           
                             
                               
                             
     1 - O comandante-geral é apoiado por um gabinete constituído pelo chefe de gabinete e pelos adjuntos, ajudante-de-campo e secretário pessoal. 
  2 - Compete ao gabinete do comandante-geral coadjuvar, assessorar e secretariar o comandante-geral no exercício das suas funções.            
         
   
     
                         
                          
  Artigo 25.º 2.º comandante-geral
                            
                           
                             
                               
                             
     1 - O 2.º comandante-geral é um tenente-general, nomeado pelo ministro da tutela, sob proposta do comandante-geral da Guarda. 
  2 - Quando o nomeado for oficial general das Forças Armadas, a nomeação é feita com o acordo do membro do Governo responsável pela área da defesa nacional. 
  3 - Ao 2.º comandante-geral compete: 
  a) Coadjuvar o comandante-geral no exercício das suas funções; 
  b) Exercer as competências que lhe forem delegadas ou subdelegadas pelo comandante-geral; 
  c) Substituir o comandante-geral nas suas ausências ou impedimentos.            
         
   
     
                         
                          
  Artigo 26.º Órgãos de inspecção, conselho e apoio geral
                            
                           
                             
                               
                             
     1 - Na dependência directa do comandante-geral funcionam os seguintes órgãos: 
  a) A Inspecção da Guarda (IG), órgão de inspecção; 
  b) O Conselho Superior da Guarda (CSG), o Conselho de Ética, Deontologia e Disciplina (CEDD) e a Junta Superior de Saúde (JSS), órgãos de conselho; 
  c) A Secretaria-Geral da Guarda (SGG), serviço de apoio geral. 
  2 - Funcionam, ainda, na dependência do comandante-geral, serviços para as áreas de estudos e planeamento, consultadoria jurídica e relações públicas.            
         
   
     
                         
                          
  Artigo 27.º Inspecção da Guarda
                            
                           
                             
                               
                             
     1 - A IG é o órgão responsável pelo desenvolvimento de acções inspectivas e de auditoria ao nível superior da Guarda, competindo-lhe apoiar o comandante-geral no exercício das suas funções de controlo e avaliação da actividade operacional, da formação, da administraç','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ão dos meios humanos, materiais e financeiros e do cumprimento das disposições legais aplicáveis e dos regulamentos e instruções internos, bem como no estudo e implementação de normas de qualidade. 
  2 - A IG é dirigida por um tenente-general, designado inspector da Guarda, na dependência directa do comandante-geral e nomeado, sob proposta deste, pelo ministro da tutela. 
  3 - O regulamento interno da IG é aprovado por despacho do ministro da tutela.            
         
   
     
                         
                          
  Artigo 28.º Conselho Superior da Guarda
                            
                           
                             
                               
                             
     1 - O CSG é o órgão máximo de consulta do comandante-geral. 
  2 - O CSG em composição restrita é constituído por: 
  a) Comandante-geral, que preside; 
  b) 2.º comandante-geral; 
  c) Inspector da Guarda; 
  d) Comandantes dos órgãos superiores de comando e direcção; 
  e) Comandante da EG. 
  3 - O CSG em composição alargada é constituído por: 
  a) Comandante-geral, que preside; 
  b) 2.º comandante-geral; 
  c) Inspector da Guarda; 
  d) Comandantes dos órgãos superiores de comando e direcção; 
  e) Comandantes das unidades territoriais, das unidades especializadas, de representação e de reserva e do estabelecimento de ensino; 
  f) Chefe da SGG; 
  g) Representantes das categorias profissionais de oficiais, sargentos e guardas, eleitos nos termos a definir por portaria do ministro da tutela. 
  4 - Por determinação do comandante-geral, podem participar nas reuniões do CSG, sem direito a voto, outras entidades que, pelas suas funções ou competência especial, o Conselho julgue conveniente ouvir. 
  5 - Compete ao CSG em composição restrita: 
  a) Aprovar o seu regimento; 
  b) Emitir parecer sobre: 
  i) Indigitação de oficiais da Guarda para a frequência de cursos de acesso a oficial general; 
  ii) Apreciação das promoções a oficial general; 
  iii) Outras questões de elevada sensibilidade e importância para a Guarda que sejam submetidas à sua apreciação pelo comandante-geral; 
  c) Exercer as competências previstas no Estatuto dos Juízes Militares e dos Assessores Militares do Ministério Público e as demais que lhe forem legalmente cometidas. 
  6 - Compete ao CSG em composição alargada aprovar o seu regimento e emitir parecer sobre: 
  a) O plano e relatório de actividades da Guarda; 
  b) Questões relevantes para a Guarda, designadamente em matéria de organização e estatuto do pessoal; 
  c) Listas de promoção por escolha e outros assuntos relativos a promoções, nos termos do Estatuto dos Militares da Guarda; 
  d) Quaisquer outros assuntos que sejam submetidos à sua apreciação pelo comandante-geral. 
  7 - Em matéria de promoções, só pode participar na discussão e votação o pessoal de graduação igual ou superior à do posto para o qual a promoção se deva efectuar.            
         
   
     
                  ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
                          
  Artigo 29.º Conselho de Ética, Deontologia e Disciplina
                            
                           
                             
                               
                             
     1 - O CEDD é o órgão de consulta do comandante-geral em matéria de justiça e disciplina. 
  2 - O CEDD tem a seguinte composição: 
  a) O comandante-geral; 
  b) O 2.º comandante-geral; 
  c) O inspector da Guarda; 
  d) Os comandantes dos órgãos superiores de comando e direcção; 
  e) Os comandantes das unidades especializadas, de representação, de intervenção e reserva e do estabelecimento de ensino; 
  f) Os comandantes de cinco unidades territoriais; 
  g) O director do serviço responsável pela área de recursos humanos; 
  h) Representantes das categorias profissionais de oficiais, sargentos e guardas, eleitos nos termos a definir por portaria do ministro da tutela. 
  3 - Compete ao CEDD emitir parecer sobre: 
  a) A aplicação das penas disciplinares de reforma compulsiva e de separação de serviço e da medida estatutária de dispensa de serviço; 
  b) Recursos disciplinares de revisão; 
  c) Quaisquer outros assuntos do âmbito da ética ou disciplina que sejam submetidos à sua apreciação pelo comandante-geral. 
  4 - O regulamento de funcionamento do CEDD é aprovado por despacho do ministro da tutela.            
         
   
     
                         
                          
  Artigo 30.º Junta Superior de Saúde
                            
                           
                             
                               
                             
     1 - A JSS é o órgão a que compete julgar o grau de capacidade para o serviço de oficiais, sargentos e guardas que, por ordem do comandante-geral, lhe forem presentes, bem como emitir parecer sobre os recursos relativos a decisões baseadas em pareceres formulados pelas juntas médicas da Guarda. 
  2 - A JSS é constituída por três médicos nomeados pelo comandante-geral, que designa, de entre eles, o presidente. 
  3 - Quando funcionar como junta de recurso, a JSS é composta por dois médicos designados pelo comandante-geral, que não tenham intervindo anteriormente no processo, e por um médico escolhido pelo requerente, o qual, não sendo indicado no prazo que para o efeito for fixado pelo comandante-geral, é substituído pelo médico que este designar.            
         
   
     
                         
                          
  Artigo 31.º Secretaria-Geral da Guarda
                            
                           
                             
                               
                             
     1 - A SGG é responsável pela elaboração e publicação da Ordem à Guarda e da Ordem de Serviço do Comando-Geral, competindo-lhe, ainda, assegurar o apoio e o enquadramento administrativo de todo o pessoal, a recepção, expedição e arquivo de toda a correspondência, a administração e o controlo das instalações, dos equi','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('pamentos e demais material e o normal funcionamento da unidade Comando-Geral. 
  2 - A SGG pode, ainda, prestar apoio administrativo a outras unidades da Guarda. 
  3 - Compete, ainda, à SGG assegurar o funcionamento da Biblioteca, do Museu e Arquivo Histórico e da Revista da Guarda.            
         
   
     
                         
                          
SECÇÃO II 
  Órgãos superiores de comando e direcção  Artigo 32.º Comando Operacional
                            
                           
                             
                               
                             
     1 - O CO assegura o comando de toda a actividade operacional da Guarda. 
  2 - O comandante do CO é um tenente-general, nomeado pelo ministro da tutela, sob proposta do comandante-geral da Guarda. 
  3 - O CO compreende as áreas de operações, informações, investigação criminal, protecção da natureza e do ambiente e missões internacionais. 
  4 - O comandante do CO tem sob o seu comando directo, para efeitos operacionais, as unidades territoriais, especializadas, de representação e de intervenção e reserva. 
  5 - O comandante do CO pode constituir comandos eventuais para operações de âmbito nacional ou regional, quando tal se justificar. 
  6 - O comandante do CO é coadjuvado por um major-general, nomeado pelo comandante-geral.            
         
   
     
                         
                          
  Artigo 33.º Comando da Administração dos Recursos Internos
                            
                           
                             
                               
                             
     1 - O CARI assegura o comando e direcção de toda a actividade da Guarda nos domínios da administração dos recursos humanos, materiais e financeiros. 
  2 - O comandante do CARI é um major-general, nomeado pelo comandante-geral. 
  3 - O CARI compreende as áreas de recursos humanos, recursos financeiros, recursos logísticos e saúde e assistência na doença. 
  4 - O CARI assegura, ainda, a assistência religiosa aos militares da Guarda.            
         
   
     
                         
                          
  Artigo 34.º Comando da Doutrina e Formação
                            
                           
                             
                               
                             
     1 - O CDF assegura o comando e direcção de toda a actividade da Guarda nos domínios da doutrina e formação do efectivo da Guarda. 
  2 - O comandante do CDF é um major-general, nomeado pelo comandante-geral. 
  3 - O CDF compreende as áreas de doutrina e formação.            
         
   
     
                         
                          
SECÇÃO IIIServiços da estrutura de comando  Artigo 35.º Serviços
                            
                           
                             
                               
                             
     O número, as competências, a estrutura interna e o posto corr','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('espondente à chefia dos serviços directamente dependentes do comandante-geral e dos serviços dos órgãos superiores de comando e direcção são definidos por decreto regulamentar.            
         
   
     
                         
                          
CAPÍTULO III Unidades SECÇÃO I Unidade do Comando da Guarda  Artigo 36.º Comando-Geral
                            
                           
                             
                               
                             
     1 - O Comando-Geral tem sede em Lisboa e concentra toda a estrutura de comando da Guarda. 
  2 - O Comando-Geral é comandado pelo chefe da SGG.            
         
   
     
                         
                          
SECÇÃO II Unidades territoriais  Artigo 37.º Comandos territoriais
                            
                           
                             
                               
                             
     1 - O comando territorial é responsável pelo cumprimento da missão da Guarda na área de responsabilidade que lhe for atribuída, na dependência directa do comandante-geral. 
  2 - Nas Regiões Autónomas dos Açores e da Madeira, os comandos territoriais têm sede em Ponta Delgada e no Funchal e, sem prejuízo de outras missões que lhes sejam especialmente cometidas, prosseguem, na respectiva área de responsabilidade, as atribuições da Guarda no âmbito da vigilância da costa e do mar territorial e da prevenção e investigação de infracções tributárias e aduaneiras, dependendo funcionalmente da Unidade de Controlo Costeiro e da Unidade de Acção Fiscal, relativamente às respectivas áreas de competência. 
  3 - Os comandos territoriais são comandados por um coronel ou tenente-coronel, coadjuvado por um 2.º comandante. 
  4 - Compete, em especial, aos comandantes de comando territorial nas regiões autónomas articular com o Governo regional a actividade operacional nas matérias cuja tutela compete à região e cooperar com os órgãos da região em matérias do âmbito das atribuições da Guarda.            
         
   
     
                         
                          
  Artigo 38.º Organização
                            
                           
                             
                               
                             
     Os comandos territoriais articulam-se em comando, serviços e subunidades operacionais.            
         
   
     
                         
                          
  Artigo 39.º Subunidades
                            
                           
                             
                               
                             
     1 - As subunidades operacionais dos comandos territoriais são os destacamentos, que se articulam localmente em subdestacamentos ou postos. 
  2 - O comando dos destacamentos e das suas subunidades é exercido por um comandante, coadjuvado por um adjunto. 
  3 - O destacamento é comandado por major ou capitão, o subdestacamento por ofic','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ial subalterno e o posto por sargento.            
         
   
     
                         
                          
  SECÇÃO III
  Unidades especializadas, de representação e de intervenção e reserva  Artigo 40.º 
Unidade de Controlo Costeiro e de Fronteiras
                            
                           
                             
                               
                             
     1 - A UCCF é a unidade especializada responsável pelo cumprimento da missão da Guarda relativamente às fronteiras marítimas e terrestres, nomeadamente:
  a) A vigilância, patrulhamento e interceção terrestre ou marítima em toda a costa e mar territorial, bem como nas fronteiras marítimas do continente e das regiões autónomas;
  b) A gestão e operação do Sistema Integrado de Vigilância, Comando e Controlo (SIVICC), distribuído ao longo da orla marítima.
  2 - A UCCF é constituída por destacamentos.
  3 - O comandante da UCCF tem o posto de major-general, sendo coadjuvado por um 2.º comandante.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 73/2021, de 12 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 63/2007, de 06 de Novembro   
     
                         
                          
  Artigo 41.º Unidade de Acção Fiscal
                            
                           
                             
                               
                             
     1 - A UAF é uma unidade especializada de âmbito nacional com competência específica de investigação para o cumprimento da missão tributária, fiscal e aduaneira cometida à Guarda. 
  2 - A UAF articula-se em destacamentos de acção fiscal e um destacamento de pesquisa de âmbito nacional. 
  3 - A UAF é comandada por um coronel, coadjuvado por um 2.º comandante.            
         
   
     
                         
                          
  Artigo 42.º Unidade Nacional de Trânsito
                            
                           
                             
                               
                             
     1 - A UNT é a unidade especializada, no âmbito da fiscalização, ordenamento e disciplina do trânsito, responsável pela uniformização de procedimentos e pela formação contínua dos militares.
  2 - Quando se justifique, a UNT pode realizar, directa e excepcionalmente, acções especiais de fiscalização em qualquer parte do território nacional abrangida pela competência territorial da Guarda Nacional Republicana, sem prejuízo das competências das respectivas unidades territoriais. 
  3 - A UNT é comandada por um coronel, coadjuvado por um 2.º comandante e o seu dispositivo será definido por portaria.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Rectif. n.º 1-A/2008, de 04 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 63/2007, de 06 de Novembro   
     
                         
                     ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
  Artigo 43.º Unidade de Segurança e Honras de Estado
                            
                           
                             
                               
                             
     1 - A USHE é uma unidade de representação responsável pela protecção e segurança às instalações dos órgãos de soberania e de outras entidades que lhe sejam confiadas e pela prestação de honras de Estado. 
  2 - A USHE articula-se em Esquadrão Presidencial, subunidade de honras de Estado e subunidade de segurança. 
  3 - Integram, ainda, a USHE a Charanga a Cavalo e a Banda da Guarda. 
  4 - A USHE é comandada por um major-general, coadjuvado por um 2.º comandante.            
         
   
     
                         
                          
  Artigo 44.º Unidade de Intervenção
                            
                           
                             
                               
                             
     1 - A UI é uma unidade da Guarda especialmente vocacionada para as missões de manutenção e restabelecimento da ordem pública, resolução e gestão de incidentes críticos, intervenção táctica em situações de violência concertada e de elevada perigosidade, complexidade e risco, segurança de instalações sensíveis e de grandes eventos, inactivação de explosivos, protecção e socorro e aprontamento e projecção de forças para missões internacionais. 
  2 - A UI articula-se em subunidades de ordem pública, de operações especiais, de protecção e socorro e de cinotecnia. 
  3 - Integram, ainda, a UI o Centro de Inactivação de Explosivos e Segurança em Subsolo (CIESS) e o Centro de Treino e Aprontamento de Forças para Missões Internacionais (CTAFMI). 
  4 - Por despacho do ministro da tutela podem ser destacadas ou colocadas com carácter permanente, forças da UI na dependência orgânica dos comandos territoriais. 
  5 - A UI é comandada por um major-general, coadjuvado por um 2.º comandante.            
         
   
     
                         
                          
SECÇÃO IV 
  Estabelecimento de ensino  Artigo 45.º Escola da Guarda
                            
                           
                             
                               
                             
     1 - A EG é uma unidade especialmente vocacionada para a formação moral, cultural, física, militar e técnico-profissional dos militares da Guarda e ainda para a actualização, especialização e valorização dos seus conhecimentos. 
  2 - A EG colabora, ainda, na formação de elementos de outras entidades, nacionais e estrangeiras. 
  3 - A EG é comandada por um major-general, coadjuvado por um 2.º comandante. 
  4 - O comandante da EG depende directamente do comandante-geral. 
  5 - A criação e extinção de centros de formação são aprovadas por portaria do ministro da tutela.            
         
   
     
                         
                          
SECÇÃO V 
  Subunidades e serviços  Artigo 46.º Subunidades
                  ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('          
                           
                             
                               
                             
     A criação e extinção de subunidades das unidades territoriais, especializadas, de representação e de intervenção e reserva e do estabelecimento de ensino são aprovadas por portaria do ministro da tutela.            
         
   
     
                         
                          
  Artigo 47.º Serviços
                            
                           
                             
                               
                             
     1 - A criação e extinção e o funcionamento dos serviços das unidades territoriais e do estabelecimento de ensino são aprovados por portaria do ministro da tutela. 
  2 - A administração das unidades especializadas, de representação e de intervenção e reserva é assegurada pela SGG e pelos serviços do CARI, nos termos a definir por portaria do ministro da tutela.            
         
   
     
                         
                          
TÍTULO III 
  Disposições financeiras  Artigo 48.º Regime financeiro
                            
                           
                             
                               
                             
     1 - A gestão financeira da Guarda rege-se pelo regime geral da contabilidade pública. 
  2 - Constituem receitas da Guarda: 
  a) As dotações atribuídas pelo Orçamento do Estado; 
  b) O produto da venda de publicações e as quantias cobradas por actividades ou serviços prestados; 
  c) Os juros dos depósitos bancários; 
  d) As receitas próprias consignadas à Guarda; 
  e) Os saldos anuais das receitas consignadas; 
  f) O valor das coimas a que tenha direito por força do cumprimento da sua missão; 
  g) Quaisquer outras receitas que lhe sejam atribuídas por lei, contrato ou a outro título.            
         
   
     
                         
                          
  Artigo 49.º Despesas
                            
                           
                             
                               
                             
     Constituem despesas da Guarda as que resultem de encargos decorrentes do funcionamento dos seus órgãos e serviços e da actividade operacional, na prossecução das atribuições que lhe estão cometidas.            
         
   
     
                         
                          
  Artigo 50.º Taxas
                            
                           
                             
                               
                             
     A actividade da Guarda pode implicar a aplicação de taxas e a cobrança de despesas a cargo de entidades que especialmente beneficiem com aquela actividade, nos termos a regular em diploma próprio.            
         
   
     
                         
                          
TÍTULO IV 
  Disposições complementares, transitórias e finais  Artigo 51.º Estruturas portuárias
                            ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
                           
                             
                               
                             
     As atribuições cometidas à Guarda em matéria de vigilância e protecção de estruturas portuárias não prejudicam o exercício das atribuições legalmente previstas de outras entidades, designadamente a Autoridade Marítima Nacional, em matéria de protecção do transporte marítimo e dos portos.            
         
   
     
                         
                          
  Artigo 52.º Disposições transitórias
                            
                           
                             
                               
                             
     1 - As atribuições cometidas à Guarda pela presente lei em matéria de vigilância, protecção e segurança de infra-estruturas aeroportuárias não prejudicam a competência atribuída à Polícia de Segurança Pública nos aeroportos internacionais actualmente existentes. 
  2 - A organização e funcionamento dos serviços sociais são regulados por diploma próprio. 
  3 - Para efeitos dos quadros anexos A e B do Regulamento de Disciplina da Guarda Nacional Republicana, aprovado pela Lei n.º 145/99, de 1 de Setembro, são estabelecidas as seguintes equiparações: 
  a) Comandante do Comando Operacional, comandante do Comando de Administração de Recursos Internos e comandante do Comando de Doutrina e Formação a chefe de estado-maior; 
  b) Comandante de estabelecimento de ensino a comandante de unidade; 
  c) 2.º comandante e director de instrução de estabelecimento de ensino a comandante de agrupamento ou de grupo destacados.            
         
   
     
                         
                          
  Artigo 53.º Regulamentação
                            
                           
                             
                               
                             
     1 - São regulados por diploma próprio: 
  a) A aplicação de taxas e a cobrança de despesas a cargo de entidades que especialmente beneficiem com a actividade da Guarda; 
  b) O estatuto remuneratório do comandante-geral. 
  2 - É regulada por decreto regulamentar a prossecução pela Guarda na zona contígua da atribuição prevista na alínea d) do n.º 2 do artigo 3.º bem como a articulação entre a Guarda e a Autoridade Marítima Nacional, no tocante às atribuições previstas nas alíneas c), e) e f) do mesmo número. 
  3 - São regulados por portaria conjunta do ministro da tutela e do membro do Governo responsável pela área das finanças os termos da ligação funcional entre a Unidade de Acção Fiscal e o Ministério das Finanças prevista no n.º 2 do artigo 13.º 
  4 - A prestação e o pagamento dos serviços requisitados à Guarda nos termos dos artigos 17.º e 18.º da presente lei são objecto de portaria conjunta do ministro da tutela, do membro do Governo responsável pela área das finanças e, quando aplicável, do membro do Governo com a tutela da entidade requisitante. 
  5 - O número, as competências, a estr','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('utura interna e o posto correspondente à chefia dos serviços de apoio directamente dependentes do comandante-geral e dos serviços dos órgãos superiores de comando e direcção são definidos por decreto regulamentar. 
  6 - São determinados por portaria do ministro da tutela: 
  a) A área de responsabilidade da Guarda, no caso de atribuições simultaneamente cometidas à Polícia de Segurança Pública, bem como das unidades territoriais e respectivas subunidades; 
  b) Os símbolos e condecoração previstos no artigo 8.º, bem como o regulamento de atribuição desta; 
  c) As condições em que o pessoal militar da Guarda pode ser afecto a organismos de interesse público; 
  d) Os termos a que obedece a eleição dos representantes dos oficiais, sargentos e guardas no CSG e no CEDD; 
  e) A criação e extinção de subunidades das unidades territoriais, especializadas, de representação e de intervenção e reserva; 
  f) A criação e extinção e o funcionamento dos serviços das unidades territoriais, bem como do estabelecimento de ensino; 
  g) Os termos em que se processa o apoio administrativo das unidades, especializadas, de representação e de intervenção e reserva pelos serviços do CARI e da SGG. 
  7 - São regulados por despacho do ministro da tutela: 
  a) Os tipos de armas em uso pela Guarda, bem como as regras do respectivo emprego; 
  b) O regulamento da IG; 
  c) O regulamento de funcionamento do CEDD.            
         
   
     
                         
                          
  Artigo 54.º Norma revogatória
                            
                           
                             
                               
                             
     É revogado o Decreto-Lei n.º 231/93, de 26 de Junho, com excepção: 
  a) Dos artigos 29.º e 30.º, cuja revogação produz efeitos com a entrada em vigor de uma nova lei de segurança interna; 
  b) Dos artigos 33.º, 92.º e 94.º, cuja revogação produz efeitos com a entrada em vigor de um novo Estatuto dos Militares da Guarda.
   Consultar o  Decreto-Lei n. 231/93, de 26 de Junho (revogado face ao diploma em epígrafe)            
         
   
     
                         
                          
  Artigo 55.º Entrada em vigor
                            
                           
                             
                               
                             
     A presente lei entra em vigor no prazo de 30 dias, com excepção do artigo 53.º, que entra em vigor no dia seguinte ao da publicação.','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:16  
    
  DL n.º 9/2012, de 18 de Janeiro  (versão actualizada) LEI ORGÂNICA DA POLÍCIA JUDICIÁRIA MILITAR    
    
 
  
                         
                          
SUMÁRIOAprova a orgânica da Polícia Judiciária Militar 
Decreto-Lei n.º 9/2012, de 18 de janeiro 
  No âmbito do Compromisso Eficiência, o XIX Governo Constitucional determinou as linhas gerais do Plano de Redução e Melhoria da Administração Central (PREMAC), afirmando que o primeiro e mais importante impulso do Plano deveria, desde logo, ser dado no processo de preparação das leis orgânicas dos ministérios e dos respectivos serviços. 
  Trata-se de algo absolutamente estruturante, por um lado, para o início de uma nova fase da reforma da Administração Pública, no sentido de a tornar eficiente e racional na utilização dos recursos públicos e, por outro, para o cumprimento dos objectivos de redução da despesa pública a que o país está vinculado. Com efeito, mais do que nunca, a concretização simultânea dos objectivos de racionalização das estruturas do Estado e de melhor utilização dos seus recursos humanos é crucial no processo de modernização e de optimização do funcionamento da Administração Pública. 
  Importava decididamente repensar e reorganizar a estrutura do Estado, no sentido de lhe dar uma maior coerência e capacidade de resposta no desempenho das funções que deverá assegurar, eliminando redundâncias e reduzindo substancialmente os seus custos de funcionamento. 
  Neste contexto, o Decreto-Lei n.º 122/2011, de 29 de Dezembro, que aprova a Lei Orgânica do Ministério da Defesa Nacional, definiu o modelo organizativo e de eficiência das estruturas e dos serviços que o integram, entre os quais a Polícia Judiciária Militar (PJM). 
  A  Lei nº 97-A/2009, de 3 de Setembro, definiu a missão e as atribuições da PJM, bem como os princípios e competências que enquadram a sua acção, enquanto corpo superior de polícia criminal auxiliar da administração da justiça. 
  Importa agora, no desenvolvimento daquela lei, determinar a estrutura orgânica da PJM e as competências da respectiva unidade orgânica nuclear, bem como fixar o número de unidades orgânicas flexíveis, traduzindo e concretizando aquelas orientações e medidas de racionalização de estruturas orgânicas, bem como de dirigentes na senda da modernização de qualificação e redução de despesa para aumento da eficiência da Administração Pública. 
  Assim: 
  Nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta o seguinte: 
  Disposição geral  Artigo 1.º Objecto
                            
                           
                             
                               
                             
     O presente decreto-lei estabelece a estrutura orgânica da Polícia Judiciária Militar, abreviadamente designada por PJM, bem como as atribuições e competências da respectiva unidade orgânica nuclear. 
  Organização e estrutura da PJM            
         
   
     
        ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                 
                          
  Artigo 2.º Direcção
                            
                           
                             
                               
                             
     A PJM é dirigida por um director-geral, cargo de direcção superior de 1.º grau.            
         
   
     
                         
                          
  Artigo 3.º Director-geral
                            
                           
                             
                               
                             
     1 - Compete ao director-geral dirigir, coordenar e orientar a acção dos órgãos e serviços da PJM, nos termos das competências que lhe são conferidas por lei ou que nele são delegadas ou subdelegadas. 
  2 - O director-geral é substituído nas suas faltas e impedimentos pelo titular do cargo de direcção intermédia de 1.º grau.            
         
   
     
                         
                          
  Artigo 4.º Estrutura
                            
                           
                             
                               
                             
     1 - A organização interna dos serviços da PJM obedece ao modelo de estrutura hierarquizada e compreende uma unidade orgânica nuclear de âmbito nacional - a Unidade de Investigação Criminal (UIC). 
  2 - A área geográfica de intervenção da UIC é a estabelecida no artigo 110.º do Código de Justiça Militar. 
  3 - O apoio técnico à UIC e a administração da PJM são garantidos por uma unidade orgânica flexível.            
         
   
     
                         
                          
  Artigo 5.º Director
                            
                           
                             
                               
                             
     1 - Compete ao director da UIC dirigir, coordenar e orientar a acção da mesma, nos termos das competências que lhe são conferidas por lei ou que nele são delegadas ou subdelegadas. 
  2 - O director da UIC é um oficial superior com o posto de capitão-de-mar-e-guerra ou coronel. 
  3 - Nas faltas e impedimentos ou em caso de vacatura do lugar, o director da UIC é substituído temporariamente pelo chefe da equipa de investigação de mais elevada graduação ou maior antiguidade, ou por oficial da unidade de investigação nomeado pelo director.            
         
   
     
                         
                          
  Artigo 6.º Competências
                            
                           
                             
                               
                             
     Compete à UIC: 
  a) Assegurar a prevenção, detecção, investigação e coadjuvação das autoridades judiciárias relativamente aos crimes da competência da PJM, e demais funções que pelo Código de Processo Penal sejam atribuídas aos órgãos de polícia criminal; 
  b) Assegurar o serviço permanente, nomeadamente de piquete e prevenção; 
  c) Fornecer a informação para','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' a base de dados de investigação criminal da PJM; 
  d) Contribuir para a elaboração do plano de actividades, orçamento e relatórios anuais e demais instrumentos de gestão.            
         
   
     
                         
                          
  Artigo 7.º Equipas de investigação
                            
                           
                             
                               
                             
     1 - A UIC desenvolve as suas competências através das equipas de investigação. 
  2 - As equipas de investigação são constituídas por um oficial investigador, chefe de equipa, e por outros investigadores, oficiais ou sargentos. 
  3 - São funções dos oficiais investigadores, chefes de equipa: 
  a) Chefiar pessoalmente as diligências de investigação criminal, planeando, distribuindo e controlando as tarefas executadas pelos investigadores da equipa; 
  b) Controlar e garantir o cumprimento de prazos processuais e das operações, acções, diligências e actos de investigação criminal, validando os respectivos relatórios; 
  c) Realizar as funções de prevenção e investigação criminais que lhe sejam cometidas pelo director da UIC; 
  d) Fornecer ao director da UIC todos os elementos de informação susceptíveis de o manter ao corrente das actividades de prevenção e investigação criminais; 
  e) Integrar os serviços de piquete e unidades de prevenção. 
  4 - São funções dos investigadores: 
  a) Realizar, sob orientação do respectivo chefe, acções e diligências de prevenção e investigação criminal e efectivar os correspondentes actos processuais; 
  b) Proceder a vigilâncias, detenções ou capturas; 
  c) Integrar os serviços de piquete e unidades de prevenção.            
         
   
     
                         
                          
  Artigo 8.º Mapa de pessoal dirigente
                            
                           
                             
                               
                             
     Os lugares de direcção superior de 1.º grau e de direcção intermédia de 1.º grau constam de mapa anexo ao presente decreto-lei, do qual faz parte integrante.            
         
   
     
                         
                          
  Artigo 9.º Nomeação do pessoal
                            
                           
                             
                               
                             
     1 - Os efectivos militares necessários ao funcionamento da PJM são assegurados em termos a definir por despacho do Ministro da Defesa Nacional e despacho dos membros do Governo responsáveis pelas áreas da defesa nacional e da administração interna, respectivamente, para os militares das Forças Armadas ou da Guarda Nacional Republicana. 
  2 - Podem ser nomeados para o desempenho dos cargos ou exercício de funções a que se refere o número anterior militares dos quadros permanentes, nas situações de activo ou de reserva, na efectividade de serviço, e militares em reg','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ime de contrato e de voluntariado. 
  3 - Os militares do activo nomeados nos termos do número anterior, prestam serviço em comissão normal. 
  4 - As comissões dos militares nomeados nos termos dos números anteriores têm a duração de três anos, podendo ser renovadas por igual ou inferior período, por razões de investimento na formação e experiência profissional adquirida. 
  5 - O disposto no número anterior carece de autorização do director-geral, considerando o interesse da PJM e do próprio, sem prejuízo de, a todo o tempo, as comissões poderem ser cessadas, por despacho fundamentado do director-geral. 
  6 - Para acederem à condição de investigadores, aos oficiais e sargentos é requerida a aprovação em curso de formação regulado por despacho do director-geral.            
         
   
     
                         
                          
  Artigo 10.º Serviço permanente
                            
                           
                             
                               
                             
     A remuneração pelo serviço permanente é determinada por portaria dos membros do Governo responsáveis pelas áreas da defesa nacional e das finanças.            
         
   
     
                         
                          
  Artigo 11.º Utilização de meios de transporte
                            
                           
                             
                               
                             
     A PJM pode fornecer ao respectivo pessoal, com carácter permanente ou temporário, meios de transporte ou títulos para utilização dos transportes colectivos, terrestres e fluviais.            
         
   
     
                         
                          
  Artigo 12.º Receitas
                            
                           
                             
                               
                             
     1 - A PJM dispõe das receitas provenientes de dotações que lhe forem atribuídas no Orçamento do Estado. 
  2 - A PJM dispõe ainda das seguintes receitas próprias: 
  a) As quantias cobradas pela prestação de serviços no âmbito das suas atribuições; 
  b) O produto da venda de publicações e de trabalhos por si editados; 
  c) Os subsídios, subvenções, comparticipações, doações e legados de entidades públicas e privadas, nacionais, estrangeiras ou internacionais; 
  d) O rendimento dos bens que possua a qualquer título; 
  e) Quaisquer receitas que por lei, contrato ou outro título lhe sejam atribuídas. 
  3 - As quantias cobradas pela PJM são fixadas e periodicamente actualizadas por despacho dos membros do Governo responsáveis pelas áreas da defesa nacional e das finanças, tendo em atenção os meios humanos e materiais mobilizados em cada caso, podendo ainda ser tidos em conta os custos indirectos de funcionamento.            
         
   
     
                         
                          
  Artigo 13.º Despesas
                            
           ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                
                             
                               
                             
     Constituem despesas da PJM as que resultem de encargos decorrentes da prossecução das atribuições que lhe estão cometidas.            
         
   
     
                         
                          
  Artigo 14.º Norma revogatória
                            
                           
                             
                               
                             
     É revogado o Decreto-Lei n.º 300/2009, de 19 de Outubro.            
         
   
     
                         
                          
  Artigo 15.º Entrada em vigor
                            
                           
                             
                               
                             
     O presente decreto-lei entra em vigor no 1.º dia do mês seguinte ao da sua publicação. 
  
  Visto e aprovado em Conselho de Ministros de 24 de Novembro de 2011. - Pedro Passos Coelho - Vítor Louçã Rabaça Gaspar - José Pedro Correia de Aguiar-Branco - Miguel Bento Martins Costa Macedo e Silva. 
  Promulgado em 5 de Janeiro de 2012. 
  Publique-se. 
  O Presidente da República, Aníbal Cavaco Silva. 
  Referendado em 9 de Janeiro de 2012. 
  O Primeiro-Ministro, Pedro Passos Coelho.            
         
   
     
                         
                          
  ANEXO
                            
                           
                             
                               
                             
     (a que se refere o artigo 8.º) 
  Mapa de pessoal dirigente
  (ver documento original)','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:69  
    
  Lei n.º 53/2007, de 31 de Agosto  (versão actualizada) LEI ORGÂNICA DA PSP    
    
 
Contém as seguintes alterações:   - Lei n.º 73/2021, de 12 de Novembro   - Lei n.º 53/2023, de 31 de Agosto   - Lei n.º 55-C/2025, de 22 de Julho  
                         
                          
SUMÁRIOAprova a orgânica da Polícia de Segurança Pública
Lei n.º 53/2007 
  de 31 de Agosto 
  Aprova a orgânica da Polícia de Segurança Pública 
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:TÍTULO IDisposições geraisCAPÍTULO INatureza, atribuições e símbolos  Artigo 1.º Definição
                            
                           
                             
                               
                             
     1 - A Polícia de Segurança de Segurança Pública, adiante designada por PSP, é uma força de segurança, uniformizada e armada, com natureza de serviço público e dotada de autonomia administrativa. 
  2 - A PSP tem por missão assegurar a legalidade democrática, garantir a segurança interna e os direitos dos cidadãos, nos termos da Constituição e da lei. 
  3 - A PSP está organizada hierarquicamente em todos os níveis da sua estrutura, estando o pessoal com funções policiais sujeito à hierarquia de comando e o pessoal sem funções policiais sujeito às regras gerais de hierarquia da função pública.            
         
   
     
                         
                          
  Artigo 2.º Dependência
                            
                           
                             
                               
                             
     A PSP depende do membro do Governo responsável pela área da administração interna e a sua organização é única para todo o território nacional.            
         
   
     
                         
                          
  Artigo 3.º 
Atribuições
                            
                           
                             
                               
                             
     1 - Em situações de normalidade institucional, as atribuições da PSP são as decorrentes da legislação de segurança interna e, em situações de excepção, as resultantes da legislação sobre a defesa nacional e sobre o estado de sítio e de emergência.
  2 - Constituem atribuições da PSP:
  a) Garantir as condições de segurança que permitam o exercício dos direitos e liberdades e o respeito pelas garantias dos cidadãos, bem como o pleno funcionamento das instituições democráticas, no respeito pela legalidade e pelos princípios do Estado de direito;
  b) Garantir a ordem e a tranquilidade públicas e a segurança e a protecção das pessoas e dos bens;
  c) Prevenir a criminalidade em geral, em coordenação com as demais forças e serviços de segurança;
  d) Prevenir a prática dos demais actos contrários à lei e aos regulamentos;
  e) Desenvolver as acções de investigação criminal e contra-ordenacional que lhe sejam a','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tribuídas por lei, delegadas pelas autoridades judiciárias ou solicitadas pelas autoridades administrativas;
  f) Velar pelo cumprimento das leis e regulamentos relativos à viação terrestre e aos transportes rodoviários e promover e garantir a segurança rodoviária, designadamente através da fiscalização, do ordenamento e da disciplina do trânsito;
  g) Garantir a execução dos actos administrativos emanados da autoridade competente que visem impedir o incumprimento da lei ou a sua violação continuada;
  h) Participar no controlo da entrada e saída de pessoas e bens no território nacional;
  i) Proteger, socorrer e auxiliar os cidadãos e defender e preservar os bens que se encontrem em situações de perigo, por causas provenientes da acção humana ou da natureza;
  j) Manter a vigilância e a protecção de pontos sensíveis, nomeadamente infra-estruturas rodoviárias, ferroviárias, aeroportuárias e portuárias, edifícios públicos e outras instalações críticas;
  l) Garantir a segurança nos espectáculos, incluindo os desportivos, e noutras actividades de recreação e lazer, nos termos da lei;
  m) Prevenir e detectar situações de tráfico e consumo de estupefacientes ou outras substâncias proibidas, através da vigilância e do patrulhamento das zonas referenciadas como locais de tráfico ou consumo;
  n) Assegurar o cumprimento das disposições legais e regulamentares referentes à protecção do ambiente, bem como prevenir e investigar os respectivos ilícitos;
  o) Participar, nos termos da lei e dos compromissos decorrentes de acordos, tratados e convenções internacionais, na execução da política externa, designadamente em operações internacionais de gestão civil de crises, de paz, e humanitárias, no âmbito policial, bem como em missões de cooperação policial internacional e no âmbito da União Europeia e na representação do País em organismos e instituições internacionais;
  p) Contribuir para a formação e informação em matéria de segurança dos cidadãos;
  q) Vigiar, fiscalizar e controlar as fronteiras aeroportuárias, assim como a circulação de pessoas nestes postos de fronteira;
  r) Assegurar a segurança de pessoas e bens, o patrulhamento, a manutenção da ordem pública e a resolução de incidentes tático-policiais nos terminais de cruzeiro integrados na fronteira marítima e localizados na sua área de jurisdição;
  s) Atribuir vistos na fronteira, nos termos da lei, nas suas áreas de jurisdição;
  t) A execução do cumprimento das decisões prévias da entidade competente de afastamento coercivo e das decisões judiciais de expulsão de cidadãos estrangeiros a concretizar por via aérea;
  u) Instruir e gerir os processos de afastamento coercivo, expulsão, readmissão e retorno voluntário de cidadãos estrangeiros, bem como elaborar normas técnicas com vista à uniformização de procedimentos;
  v) Executar os afastamentos e as decisões judiciais de expulsão de cidadãos estrangeiros a concretizar por via aérea;
  x) Assegurar a execução dos processos de readmissão, a con','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('cretizar por via aérea;
  z) Assegurar a realização de controlos móveis e de operações conjuntas com serviços ou forças de segurança congéneres, nacionais ou estrangeiros, nas suas áreas de jurisdição;
  aa) Gerir os centros de instalação temporária e os espaços equiparados;
  bb) Fiscalizar a permanência de estrangeiros em território nacional na sua área de jurisdição;
  cc) Prosseguir as demais atribuições que lhe forem cometidas por lei.
  3 - Constituem ainda atribuições da PSP:
  a) Licenciar, controlar e fiscalizar o fabrico, armazenamento, comercialização, uso e transporte de armas, munições e substâncias explosivas e equiparadas que não pertençam ou se destinem às Forças Armadas e demais forças e serviços de segurança, sem prejuízo das competências de fiscalização legalmente cometidas a outras entidades;
  b) Licenciar, controlar e fiscalizar as actividades de segurança privada e respectiva formação, em cooperação com as demais forças e serviços de segurança e com a Inspecção-Geral da Administração Interna;
  c) Garantir a segurança pessoal dos membros dos órgãos de soberania e de altas entidades nacionais ou estrangeiras, bem como de outros cidadãos, quando sujeitos a situação de ameaça relevante;
  d) Assegurar o ponto de contacto permanente para intercâmbio internacional de informações relativas aos fenómenos de violência associada ao desporto.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 73/2021, de 12 de Novembro   - Lei n.º 53/2023, de 31 de Agosto   - Lei n.º 55-C/2025, de 22 de Julho
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 53/, de 2007 de Agosto    - 2ª versão: Lei n.º 73/2021, de 12 de Novembro    - 3ª versão: Lei n.º 53/2023, de 31 de Agosto   
     
                         
                          
  Artigo 4.º Conflitos de natureza privada
                            
                           
                             
                               
                             
     A PSP não pode dirimir conflitos de natureza privada, devendo, nesses casos, limitar a sua acção à manutenção da ordem pública.            
         
   
     
                         
                          
  Artigo 5.º Âmbito territorial
                            
                           
                             
                               
                             
     1 - As atribuições da PSP são prosseguidas em todo o território nacional. 
  2 - No caso de atribuições cometidas simultaneamente à Guarda Nacional Republicana, a área de responsabilidade da PSP é definida por portaria do ministro da tutela. 
  3 - Fora da área de responsabilidade definida nos termos do número anterior, a intervenção da PSP depende: 
  a) Do pedido de outra força de segurança; 
  b) De ordem especial; 
  c) De imposição legal. 
  4 - A PSP pode prosseguir a sua missão fora do território nacional, desde que legalmente mandatada para esse efeito.            
    ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
   
     
                         
                          
  Artigo 6.º Deveres de colaboração
                            
                           
                             
                               
                             
     1 - A PSP, sem prejuízo das prioridades legais da sua actuação, coopera com as demais forças e serviços de segurança, bem como com as autoridades públicas, designadamente, com os órgãos autárquicos e outros organismos, nos termos da lei. 
  2 - As autoridades da administração central, regional e local, os serviços públicos e as demais entidades públicas ou privadas devem prestar à PSP a colaboração que legitimamente lhes for solicitada para o exercício das suas funções. 
  3 - As autoridades administrativas devem comunicar à PSP, quando solicitado, o teor das decisões sobre as infracções que esta lhes tenha participado.            
         
   
     
                         
                          
  Artigo 7.º Estandarte nacional
                            
                           
                             
                               
                             
     A PSP e as suas unidades de polícia, incluindo as unidades constituídas para actuar fora do território nacional, e os estabelecimentos de ensino policial, têm direito ao uso do estandarte nacional.            
         
   
     
                         
                          
  Artigo 8.º Símbolos
                            
                           
                             
                               
                             
     1 - A PSP tem direito a brasão de armas, bandeira heráldica, hino e selo branco. 
  2 - A Direcção Nacional, as unidades de polícia e os estabelecimentos de ensino têm direito a brasão de armas, bandeiras heráldicas e selo branco. 
  3 - O director nacional tem direito ao uso de galhardete. 
  4 - Os símbolos previstos nos números anteriores são aprovados por portaria do ministro da tutela.            
         
   
     
                         
                          
CAPÍTULO IIAutoridades e órgãos de polícia  Artigo 9.º Comandantes e agentes de força pública
                            
                           
                             
                               
                             
     1 - Os elementos da PSP no exercício do comando de forças têm a categoria de comandantes de força pública. 
  2 - Considera-se força pública, para efeitos do número anterior, o efectivo mínimo de dois agentes em missão de serviço. 
  3 - Os elementos da PSP com funções policiais são considerados agentes da força pública e de autoridade quando lhes não deva ser atribuído qualidade superior.            
         
   
     
                         
                          
  Artigo 10.º Autoridades de polícia
                            
                           
                             
                               
                     ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('        
     1 - São consideradas autoridades de polícia: 
  a) O director nacional; 
  b) Os directores nacionais-adjuntos; 
  c) O inspector nacional; 
  d) O comandante da Unidade Especial de Polícia; 
  e) Os comandantes das unidades e subunidades até ao nível de esquadra; 
  f) Outros oficiais da PSP, quando no exercício de funções de comando ou chefia operacional. 
  2 - Compete às autoridades de polícia referidas no número anterior determinar a aplicação das medidas de polícia previstas na lei.            
         
   
     
                         
                          
  Artigo 11.º Autoridades e órgãos de polícia criminal
                            
                           
                             
                               
                             
     1 - Para efeitos do disposto no Código de Processo Penal, consideram-se: 
  a) Autoridades de polícia criminal, as entidades referidas no n.º 1 do artigo anterior; 
  b) Órgãos de polícia criminal, todos os elementos da PSP com funções policiais incumbidos de realizar quaisquer actos ordenados por autoridade judiciária ou determinados por aquele Código. 
  2 - Enquanto órgãos de polícia criminal, e sem prejuízo da organização hierárquica da PSP, o pessoal com funções policiais da PSP actua sob a direcção e na dependência funcional da autoridade judiciária competente. 
  3 - Os actos determinados pelas autoridades judiciárias são realizados pelos elementos para esse efeito designados pela respectiva cadeia de comando, no âmbito da sua autonomia técnica e táctica.            
         
   
     
                         
                          
  Artigo 12.º Medidas de polícia e meios de coerção
                            
                           
                             
                               
                             
     1 - No âmbito das suas atribuições, a PSP utiliza as medidas de polícia legalmente previstas e nas condições e termos da Constituição e da lei de segurança interna, não podendo impor restrições ou fazer uso dos meios de coerção para além do estritamente necessário. 
  2 - Quem faltar à obediência devida a ordem ou a mandado legítimos, regularmente comunicados e emanados de autoridade de polícia ou agente de autoridade da PSP, é punido com a pena legalmente prevista para a desobediência qualificada.            
         
   
     
                         
                          
CAPÍTULO IIIPrestação e requisição de serviços  Artigo 13.º Requisição de forças
                            
                           
                             
                               
                             
     1 - As autoridades judiciárias e administrativas podem requisitar à PSP a actuação de forças para a manutenção da ordem e tranquilidade públicas. 
  2 - A requisição de forças é apresentada junto da autoridade de polícia territorialmente competente, indicando a natureza do serviço a desempenhar e o motivo ou ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a ordem que as justifica. 
  3 - As forças requisitadas actuam no quadro das suas competências e de forma a cumprirem a sua missão, mantendo total subordinação aos comandos de que dependem.            
         
   
     
                         
                          
  Artigo 14.º Prestação de serviços especiais
                            
                           
                             
                               
                             
     1 - A PSP pode manter pessoal com funções policiais em organismos de interesse público, em condições definidas por portaria do ministro da tutela. 
  2 - O pessoal da PSP pode ser nomeado em comissão de serviço para organismos internacionais ou países estrangeiros, em função dos interesses nacionais e dos compromissos assumidos no âmbito da cooperação internacional, nos termos legalmente estabelecidos. 
  3 - O pessoal referido no n.º 1 cumpre, para efeitos de ordem pública, as directivas do comando com jurisdição na respectiva área. 
  4 - A PSP pode ainda prestar serviços especiais, mediante solicitação, que, após serem autorizados pela entidade competente, são remunerados pelos respectivos requisitantes nos termos que forem regulamentados.            
         
   
     
                         
                          
  Artigo 15.º Prestação de serviços a outros organismos públicos
                            
                           
                             
                               
                             
     1 - Sem prejuízo da missão que lhe está cometida e no âmbito do dever de coadjuvação dos tribunais, a PSP pode afectar pessoal com funções policiais para a realização das actividades de comunicação dos actos processuais previstos no Código de Processo Penal. 
  2 - A PSP pode ainda afectar pessoal com funções policiais para prestar serviço a órgãos e entidades da administração central, regional e local. 
  3 - A prestação e o pagamento das acções previstas nos números anteriores, quando não regulados por lei especial, são objecto de portaria conjunta dos membros do Governo responsáveis pelas áreas da administração interna e das finanças e pela tutela da entidade requisitante.            
         
   
     
                         
                          
  Artigo 16.º Colaboração com entidades públicas e privadas
                            
                           
                             
                               
                             
     1 - Sem prejuízo do cumprimento da sua missão, a PSP pode prestar colaboração a outras entidades públicas ou privadas que a solicitem, para garantir a segurança de pessoas e bens ou para a prestação de outros serviços, mediante pedidos concretos que lhe sejam formulados, os quais serão sujeitos a decisão caso a caso. 
  2 - A administração central poderá estabelecer protocolos com as autarquias locais para a execução das responsabilidades de construção, aquisição ou beneficiação ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('de instalações e edifícios para a PSP sempre que as razões de oportunidade e conveniência o aconselhem. 
  3 - O pagamento dos serviços efectuados pela PSP ao abrigo do n.º 1 é regulado na portaria referida no n.º 3 do artigo anterior.            
         
   
     
                         
                          
TÍTULO IIOrganização geralCAPÍTULO IDisposições gerais  Artigo 17.º Estrutura geral
                            
                           
                             
                               
                             
     A PSP compreende: 
  a) A Direcção Nacional; 
  b) As unidades de polícia; 
  c) Os estabelecimentos de ensino policial.            
         
   
     
                         
                          
  Artigo 18.º 
Direcção Nacional
                            
                           
                             
                               
                             
     1 - A Direcção Nacional compreende:
  a) O director nacional;
  b) Os directores nacionais-adjuntos;
  c) O Conselho Superior de Polícia, o Conselho de Deontologia e Disciplina e a Junta Superior de Saúde;
  d) A Inspecção;
  e) As unidades orgânicas de operações e segurança, de estrangeiros, fronteiras e segurança aeroportuária, de recursos humanos e de logística e finanças.
  2 - Funcionam, ainda, na dependência do director nacional, o Departamento de Apoio Geral e serviços para as áreas de estudos e planeamento, consultadoria jurídica, deontologia e disciplina, relações públicas e assistência religiosa.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 73/2021, de 12 de Novembro   - Lei n.º 55-C/2025, de 22 de Julho
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 53/2007, de 31 de Agosto    - 2ª versão: Lei n.º 73/2021, de 12 de Novembro   
     
                         
                          
  Artigo 19.º Unidades de polícia
                            
                           
                             
                               
                             
     1 - Na PSP existem as seguintes unidades de polícia: 
  a) Unidade Especial de Polícia; 
  b) Os comandos territoriais de polícia. 
  2 - São comandos territoriais de polícia: 
  a) Os comandos regionais de polícia; 
  b) Os Comandos Metropolitanos de Polícia de Lisboa e do Porto; 
  c) Os comandos distritais de polícia. 
  3 - Podem ser constituídas unidades de polícia para cumprimento de missões fora do território nacional, nos termos da lei.            
         
   
     
                         
                          
  Artigo 20.º Estabelecimentos de ensino policial
                            
                           
                             
                               
                             
     São estabelecimentos de ensino policial: 
  a) O Instituto Superior de Ciências Policiais e Segurança Interna; 
  b) A Escola Prática de Polícia.     ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
         
   
     
                         
                          
  CAPÍTULO II
  Direcção Nacional
  SECÇÃO I
  Director nacional  Artigo 21.º 
Competência
                            
                           
                             
                               
                             
     1 - Ao director nacional compete, em geral, comandar, dirigir, coordenar, gerir, controlar e fiscalizar todos os órgãos, comandos, serviços e estabelecimentos de ensino da PSP.
  2 - Além das competências próprias dos cargos de direcção superior de 1.º grau, compete ao director nacional:
  a) Representar a PSP;
  b) Presidir ao Conselho Superior de Polícia;
  c) Presidir ao Conselho de Deontologia e Disciplina;
  d) Colocar e transferir o pessoal com funções policiais e não policiais, de acordo com as necessidades do serviço;
  e) Exercer o poder disciplinar;
  f) Autorizar o desempenho pela PSP de serviços de carácter especial a pedido de outras entidades;
  g) Determinar a realização de inspecções aos órgãos e serviços da PSP em todos os aspectos da sua actividade;
  h) Sancionar as licenças arbitradas pelas juntas de saúde;
  i) Homologar as decisões da Junta Superior de Saúde;
  j) Conceder licenças, autorizações e exercer as demais competências administrativas previstas na lei;
  l) Exercer as competências que lhe forem delegadas.
  3 - O director nacional pode delegar em todos os níveis de pessoal dirigente as suas competências próprias, salvo se a lei expressamente o impedir.
  4 - A competência referida na alínea a) do n.º 2 é delegável em qualquer elemento do pessoal dirigente dos quadros de pessoal da PSP.
  5 - O diretor nacional é coadjuvado por quatro diretores nacionais-adjuntos, que dirigem, respetivamente, as unidades orgânicas de operações e segurança, estrangeiros, fronteiras e segurança aeroportuária, de recursos humanos e de logística e finanças.
  6 - O director nacional é substituído, nas suas faltas ou impedimentos, pelo director nacional-adjunto que dirige a unidade orgânica de operações e segurança.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 73/2021, de 12 de Novembro   - Lei n.º 55-C/2025, de 22 de Julho
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 53/2007, de 31 de Agosto    - 2ª versão: Lei n.º 73/2021, de 12 de Novembro   
     
                         
                          
  Artigo 22.º Gabinete
                            
                           
                             
                               
                             
     1 - O director nacional é apoiado por um gabinete constituído pelo chefe de gabinete e pelos adjuntos e secretário pessoal. 
  2 - Compete ao Gabinete do director nacional coadjuvar, assessorar e secretariar o director nacional no exercício das suas funções. 
  3 - O Gabinete é dirigido por um chefe de gabinete, cargo de direcção intermédia de 1.º grau.            
         
   
   ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  
                         
                          
  Artigo 23.º Directores nacionais-adjuntos
                            
                           
                             
                               
                             
     Compete aos directores nacionais-adjuntos: 
  a) Coadjuvar o director nacional no exercício das suas funções; 
  b) Exercer a direcção e coordenação da unidade orgânica que lhe for atribuída por despacho do director nacional; 
  c) Exercer as competências delegadas ou subdelegadas pelo director nacional.            
         
   
     
                         
                          
SECÇÃO IIÓrgãos de inspecção e consulta  Artigo 24.º Órgãos de inspecção e consulta
                            
                           
                             
                               
                             
     Na dependência directa do director nacional funcionam os seguintes órgãos: 
  a) A Inspecção; 
  b) O Conselho Superior de Polícia, o Conselho de Deontologia e Disciplina e a Junta Superior de Saúde, órgãos de consulta.            
         
   
     
                         
                          
  Artigo 25.º Inspecção
                            
                           
                             
                               
                             
     1 - A Inspecção é o serviço, directamente dependente do director nacional, que exerce o controlo interno nos domínios operacional, administrativo, financeiro e técnico, competindo-lhe verificar, acompanhar, avaliar e informar sobre a actuação de todos os serviços da PSP, tendo em vista promover: 
  a) A legalidade, a regularidade, a eficácia e a eficiência da actividade operacional, da gestão orçamental e patrimonial e da gestão de pessoal; 
  b) A qualidade do serviço prestado à população; 
  c) O cumprimento dos planos de actividades e das decisões e instruções internas. 
  2 - A Inspecção é dirigida pelo inspector nacional. 
  3 - O regulamento interno da Inspecção é aprovado por despacho do ministro da tutela.            
         
   
     
                         
                          
  Artigo 26.º Conselho Superior de Polícia
                            
                           
                             
                               
                             
     1 - O Conselho Superior de Polícia (CSP) é um órgão consultivo do director nacional ao qual compete pronunciar-se sobre os assuntos relativos à actividade da PSP e sua relação com as populações, apoiar a decisão do director nacional em assuntos de particular relevância e, em especial: 
  a) Emitir parecer sobre os objectivos, necessidades e planos estratégicos da PSP e a sua execução; 
  b) Pronunciar-se sobre as providências legais ou regulamentares que digam respeito à PSP, quando solicitado; 
  c) Pronunciar-se, a solicitação do ministro da tutela, sobre quaisquer assuntos que digam respeito à PSP. 
  2 - Compõem o CS','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('P: 
  a) O director nacional, que preside; 
  b) Os directores nacionais-adjuntos; 
  c) O inspector nacional; 
  d) Os comandantes regionais dos Açores e da Madeira; 
  e) Os comandantes metropolitanos de Lisboa e Porto e da Unidade Especial de Polícia; 
  f) Os directores dos estabelecimentos de ensino policial; 
  g) Os directores dos serviços responsáveis pelas áreas de operações, recursos humanos e logística; 
  h) Três comandantes distritais, a nomear pelo director nacional; 
  i) Quatro vogais eleitos de entre os candidatos apresentados pelas associações sindicais, nos termos da lei; 
  j) Um vogal eleito de entre os oficiais de posto de superintendente-chefe, superintendente e intendente; 
  l) Dois vogais eleitos de entre os subintendentes, comissários e subcomissários; 
  m) Três vogais eleitos de entre os elementos da carreira de chefe; 
  n) Cinco vogais eleitos de entre os elementos da carreira de agente; 
  o) Um vogal eleito de entre os funcionários pertencentes ao quadro de pessoal sem funções policiais. 
  3 - A forma de designação e eleição dos membros do CSP e o seu regulamento de funcionamento são aprovados por portaria do ministro da tutela.            
         
   
     
                         
                          
  Artigo 27.º Conselho de Deontologia e Disciplina
                            
                           
                             
                               
                             
     1 - O Conselho de Deontologia e Disciplina (CDD) é um órgão de carácter consultivo do director nacional, ao qual compete apreciar e emitir parecer sobre os assuntos que lhe sejam submetidos em matéria de deontologia e disciplina e exercer as competências que a lei e o regulamento disciplinar lhe conferem. 
  2 - Compõem o CDD: 
  a) O director nacional, que preside; 
  b) Os directores nacionais-adjuntos; 
  c) O inspector nacional; 
  d) Um comandante regional de polícia a designar pelo director nacional; 
  e) Um comandante metropolitano de polícia, a designar pelo director nacional; 
  f) Dois comandantes distritais de polícia, a designar pelo director nacional; 
  g) O director do serviço responsável pela área de deontologia e disciplina; 
  h) Três vogais eleitos de entre os candidatos apresentados pelas associações sindicais, nos termos da lei. 
  3 - O regulamento de funcionamento do CDD e a forma de designação e eleição dos membros é aprovado por portaria do ministro da tutela.            
         
   
     
                         
                          
  Artigo 28.º Junta Superior de Saúde
                            
                           
                             
                               
                             
     1 - A Junta Superior de Saúde (JSS) é o órgão a que compete julgar o grau de capacidade para o serviço do pessoal da PSP que, por ordem do director nacional, lhe for presente, bem como emitir parecer sobre os recursos relativos a decisões baseadas em ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('pareceres formulados pelas juntas médicas da PSP. 
  2 - A JSS é constituída por três médicos nomeados pelo director nacional, que designa, de entre eles, o presidente. 
  3 - Quando funcionar como junta de recurso, a JSS é composta por dois médicos designados pelo director nacional, que não tenham intervindo anteriormente no processo, e por um médico escolhido pelo requerente, o qual, não sendo indicado no prazo que para o efeito for fixado pelo director nacional, é substituído pelo médico que este designar.            
         
   
     
                         
                          
SECÇÃO IIIUnidades orgânicas  Artigo 29.º Operações e segurança
                            
                           
                             
                               
                             
     A unidade orgânica de operações e segurança compreende as áreas de operações, informações policiais, investigação criminal, armas e explosivos, segurança privada, sistemas de informação e comunicações.            
         
   
     
                         
                          
  Artigo 29.º-A 
Estrangeiros, fronteiras e segurança aeroportuária
                            
                           
                             
                               
                             
     1 - A unidade orgânica de estrangeiros, fronteiras e segurança aeroportuária compreende a Unidade Nacional de Estrangeiros e Fronteiras (UNEF).
  2 - A UNEF compreende as seguintes áreas:
  a) Gestão de fronteiras aeroportuárias;
  b) Segurança aeroportuária;
  c) Retorno e instalação temporária;
  d) Controlo e fiscalização da permanência e da atividade de cidadãos estrangeiros em território nacional, na área de jurisdição da PSP.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 55-C/2025, de 22 de Julho
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 73/2021, de 12 de Novembro   
     
                         
                          
  Artigo 30.º Recursos humanos
                            
                           
                             
                               
                             
     A unidade orgânica de recursos humanos compreende as áreas de recursos humanos, formação e saúde e assistência na doença.            
         
   
     
                         
                          
  Artigo 31.º Logística e finanças
                            
                           
                             
                               
                             
     A unidade orgânica de logística e finanças compreende as áreas de logística e gestão financeira.            
         
   
     
                         
                          
  Artigo 32.º Serviços
                            
                           
                             
                               
                             
     O número, as competências, ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a estrutura interna e os cargos de direcção dos serviços das unidades orgânicas são definidos por portaria, nos termos da Lei n.º 4/2004, de 15 de Janeiro, que estabelece os princípios e as normas a que deve obedecer a organização da administração directa do Estado.            
         
   
     
                         
                          
SECÇÃO IVApoio geral  Artigo 33.º Departamento de Apoio Geral
                            
                           
                             
                               
                             
     1 - Ao Departamento de Apoio Geral (DAG) compete o enquadramento administrativo, para efeitos operacionais e de disciplina, do pessoal, bem como a administração e o controlo das instalações, dos equipamentos e demais material, e a recepção, expedição e arquivo de toda a correspondência, da Direcção Nacional. 
  2 - O DAG pode, ainda, prestar apoio administrativo a outras unidades da PSP. 
  3 - Compete, ainda, ao DAG assegurar o funcionamento da Biblioteca, do Arquivo Central, do Museu e da Banda da PSP. 
  4 - A Biblioteca da PSP funciona junto do Instituto Superior de Ciências Policiais e Segurança Interna, integrando o seu actual acervo bibliográfico.            
         
   
     
                         
                          
CAPÍTULO IIIUnidades de políciaSECÇÃO IComandos territoriais de polícia  Artigo 34.º Caracterização
                            
                           
                             
                               
                             
     1 - Os comandos territoriais de polícia são unidades territoriais na dependência directa do director nacional que prosseguem as atribuições da PSP na respectiva área de responsabilidade. 
  2 - Em cada uma das Regiões Autónomas dos Açores e da Madeira existe um comando regional de polícia, com sede, respectivamente, em Ponta Delgada e no Funchal. 
  3 - Os Comandos Metropolitanos de Polícia têm sede em Lisboa e no Porto. 
  4 - Os comandos distritais de polícia têm sede em Aveiro, Beja, Braga, Bragança, Castelo Branco, Coimbra, Évora, Faro, Guarda, Leiria, Portalegre, Santarém, Setúbal, Viana do Castelo, Vila Real e Viseu.            
         
   
     
                         
                          
  Artigo 35.º Organização
                            
                           
                             
                               
                             
     Os comandos territoriais de polícia compreendem o comando, serviços e subunidades.            
         
   
     
                         
                          
  Artigo 36.º Comandantes regionais, metropolitanos e distritais
                            
                           
                             
                               
                             
     1 - Aos comandantes regionais, metropolitanos e distritais de polícia, na sua área de responsabilidade, compete: 
  a) Representar a PSP; 
  b) Exe','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rcer o comando do respectivo comando territorial, através da gestão e emprego dos meios humanos, materiais e financeiros que lhe estão atribuídos; 
  c) Nomear os comandantes das subunidades; 
  d) Colocar e transferir o pessoal de acordo com as necessidades do serviço; 
  e) Exercer o poder disciplinar; 
  f) Determinar inspecções a todas as actividades do comando e das subunidades; 
  g) Exercer as competências delegadas, ou subdelegadas, pelo director nacional, bem como executar e fazer executar todas as determinações deste; 
  h) Exercer todas as demais competências previstas legalmente em matéria de segurança pública e privada. 
  2 - Os comandantes regionais, metropolitanos e distritais de polícia podem delegar as suas competências nos respectivos 2.os comandantes, salvo se a lei expressamente o impedir. 
  3 - Compete, em especial, aos comandantes regionais de polícia: 
  a) O comando de todas as forças da PSP na área da respectiva Região Autónoma; 
  b) Promover as acções de fiscalização do cumprimento das disposições legais e regulamentares sobre viação terrestre e transportes rodoviários em todas as vias públicas; 
  c) Articular com o Governo Regional a actividade operacional nas matérias cuja tutela compete à Região; 
  d) Manter informados os órgãos de governo próprio da Região da situação de segurança no respectivo território; 
  e) Cooperar com os órgãos da Região em matérias do âmbito das atribuições da PSP e na resolução dos problemas relacionados com as funções policiais que desempenham. 
  4 - O comandante regional de polícia dos Açores pode delegar as suas competências nos comandantes de divisão. 
  5 - A competência referida na alínea a) do n.º 1 é delegável em qualquer elemento dos quadros da PSP do respectivo comando.            
         
   
     
                         
                          
  Artigo 37.º 2.º comandante
                            
                           
                             
                               
                             
     1 - Os comandantes regionais, metropolitanos e distritais de polícia são coadjuvados por um 2.º comandante. 
  2 - Os 2.os comandantes substituem, nas suas faltas ou impedimentos, o respectivo comandante e, são substituídos, nas suas faltas ou impedimentos, pelo oficial mais graduado ou, se houver vários de igual graduação, pelo mais antigo.            
         
   
     
                         
                          
  Artigo 38.º Subunidades
                            
                           
                             
                               
                             
     1 - As subunidades dos comandos territoriais de polícia são a divisão policial e a esquadra. 
  2 - As divisões policiais compreendem as áreas operacional e administrativa. 
  3 - As esquadras são subunidades operacionais.            
         
   
     
                         
                          
  Artigo 39.º Comando de subunidades
       ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                     
                           
                             
                               
                             
     1 - O comando das subunidades é exercido por um comandante, coadjuvado por um adjunto. 
  2 - Salvo designação em contrário do comandante do comando territorial de polícia, o adjunto é o elemento mais graduado colocado na respectiva subunidade. 
  3 - Caso existam vários elementos com a mesma graduação, prefere o mais antigo.            
         
   
     
                         
                          
SECÇÃO IIUnidade Especial de Polícia  Artigo 40.º Missão
                            
                           
                             
                               
                             
     A Unidade Especial de Polícia (UEP) é uma unidade especialmente vocacionada para operações de manutenção e restabelecimento da ordem pública, resolução e gestão de incidentes críticos, intervenção táctica em situações de violência concertada e de elevada perigosidade, complexidade e risco, segurança de instalações sensíveis e de grandes eventos, segurança pessoal dos membros dos órgãos de soberania e de altas entidades, inactivação de explosivos e segurança em subsolo e aprontamento e projecção de forças para missões internacionais.            
         
   
     
                         
                          
  Artigo 41.º Organização
                            
                           
                             
                               
                             
     1 - A UEP compreende as seguintes subunidades operacionais: 
  a) O Corpo de Intervenção; 
  b) O Grupo de Operações Especiais; 
  c) O Corpo de Segurança Pessoal; 
  d) O Centro de Inactivação de Explosivos e Segurança em Subsolo; 
  e) O Grupo Operacional Cinotécnico. 
  2 - Por despacho do ministro da tutela, sob proposta do director nacional, podem ser destacadas, ou colocadas com carácter permanente, forças da UEP na dependência operacional, logística e administrativa dos comandos territoriais de polícia.            
         
   
     
                         
                          
  Artigo 42.º Corpo de Intervenção
                            
                           
                             
                               
                             
     O Corpo de Intervenção (CI) constitui uma força de reserva à ordem do director nacional, especialmente preparada e destinada a ser utilizada em: 
  a) Acções de manutenção e reposição de ordem pública; 
  b) Combate a situações de violência concertada; 
  c) Colaboração com os comandos no patrulhamento, em condições a definir por despacho do director nacional.            
         
   
     
                         
                          
  Artigo 43.º Grupo de Operações Especiais
                            
                           
                             
                               
                         ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('    
     O Grupo de Operações Especiais (GOE) constitui uma força de reserva da PSP, à ordem do director nacional, destinada, fundamentalmente, a combater situações de violência declarada, cuja resolução ultrapasse os meios normais de actuação.            
         
   
     
                         
                          
  Artigo 44.º Corpo de Segurança Pessoal
                            
                           
                             
                               
                             
     O Corpo de Segurança Pessoal (CSP) é uma força especialmente preparada e vocacionada para a segurança pessoal de altas entidades, membros de órgãos de soberania, protecção policial de testemunhas ou outros cidadãos sujeitos a ameaça, no âmbito das atribuições da PSP.            
         
   
     
                         
                          
  Artigo 45.º Centro de Inactivação de Explosivos e Segurança em Subsolo
                            
                           
                             
                               
                             
     O Centro de Inactivação de Explosivos e Segurança em Subsolo (CIEXSS) é um núcleo de direcção e formação técnica da especialidade de detecção e inactivação de engenhos explosivos e de segurança no subsolo.            
         
   
     
                         
                          
  Artigo 46.º Grupo Operacional Cinotécnico
                            
                           
                             
                               
                             
     O Grupo Operacional Cinotécnico (GOC) é uma subunidade especialmente preparada e vocacionada para a aplicação de canídeos no quadro de competências da PSP.            
         
   
     
                         
                          
  Artigo 47.º Comandante da UEP
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no n.º 1 do artigo 57.º, o comandante da UEP tem as competências previstas para os comandantes territoriais de polícia.            
         
   
     
                         
                          
SECÇÃO IIISubunidades e serviços  Artigo 48.º Subunidades
                            
                           
                             
                               
                             
     A criação e extinção de subunidades dos comandos territoriais de polícia e da UEP são aprovadas por portaria do ministro da tutela.            
         
   
     
                         
                          
  Artigo 49.º Serviços
                            
                           
                             
                               
                             
     A criação e extinção e o funcionamento dos serviços dos comandos territoriais de polícia e da UEP são aprovados por portaria do ministro da tu','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tela.            
         
   
     
                         
                          
CAPÍTULO IVEstabelecimentos de ensino policial  Artigo 50.º Instituto Superior de Ciências Policiais e Segurança Interna
                            
                           
                             
                               
                             
     1 - O Instituto Superior de Ciências Policiais e Segurança Interna (ISCPSI) é um instituto policial de ensino superior universitário que tem por missão formar oficiais de polícia, promover o seu aperfeiçoamento permanente e realizar, coordenar ou colaborar em projectos de investigação e desenvolvimento no domínio das ciências policiais. 
  2 - O ISCPSI confere, nos termos da lei, graus académicos na sua área científica. 
  3 - A organização e funcionamento do ISCPSI são definidos por decreto regulamentar.            
         
   
     
                         
                          
  Artigo 51.º Escola Prática de Polícia
                            
                           
                             
                               
                             
     1 - A Escola Prática de Polícia (EPP) é um estabelecimento de ensino policial, na dependência do director nacional, que tem por missão ministrar cursos e estágios de formação, aperfeiçoamento e actualização de agentes e chefes, e de especialização para todo o pessoal da PSP. 
  2 - A organização e funcionamento da EPP são definidos por decreto regulamentar.            
         
   
     
                         
                          
TÍTULO IIIProvimento  Artigo 52.º Director nacional
                            
                           
                             
                               
                             
     1 - O recrutamento para o cargo de director nacional é feito, por escolha, de entre superintendentes-chefes, ou indivíduos licenciados de reconhecida idoneidade e experiência profissional, vinculados ou não à Administração Pública. 
  2 - O provimento do cargo é feito mediante despacho conjunto do Primeiro-Ministro e do ministro da tutela. 
  3 - O cargo é provido em comissão de serviço por um período de três anos, renovável por iguais períodos. 
  4 - A renovação da comissão de serviço deverá ser comunicada ao interessado até 30 dias antes do seu termo, cessando a mesma automaticamente no final do respectivo período se o ministro da tutela não tiver manifestado expressamente a intenção de a renovar, caso em que o dirigente se manterá no exercício de funções de gestão corrente até à nomeação do novo titular do cargo. 
  5 - Para efeitos de eventual renovação da comissão de serviço, deve a entidade competente ser informada, com a antecedência mínima de 90 dias, do termo de cada comissão, cessando esta automaticamente no fim do respectivo período sempre que não seja dado cumprimento àquela formalidade. 
  6 - Em qualquer momento, a comissão de serviço pode ser dada por finda p','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('or despacho do ministro da tutela, por iniciativa deste ou a requerimento do interessado.            
         
   
     
                         
                          
  Artigo 53.º Director nacional-adjunto
                            
                           
                             
                               
                             
     1 - O recrutamento para o cargo de director nacional-adjunto é feito, por escolha, de entre superintendentes-chefes, ou de entre indivíduos licenciados de reconhecida idoneidade e experiência profissional, vinculados ou não à Administração Pública. 
  2 - O director nacional-adjunto que dirige a unidade orgânica de operações e segurança, é sempre um superintendente-chefe. 
  3 - O provimento é feito mediante despacho do ministro da tutela, sendo aplicável o disposto nos n.os 3, 4 e 5 do artigo anterior. 
  4 - Em qualquer momento, a comissão de serviço pode ser dada por finda por despacho do ministro da tutela, por iniciativa deste, por proposta do director nacional, ou a requerimento do interessado.            
         
   
     
                         
                          
  Artigo 54.º Inspector nacional
                            
                           
                             
                               
                             
     1 - O recrutamento para o cargo de inspector nacional é feito, por escolha, de entre superintendentes-chefes. 
  2 - É aplicável à comissão de serviço do inspector nacional, o regime previsto nos n.os 3 e 4 do artigo anterior com as devidas adaptações.            
         
   
     
                         
                          
  Artigo 55.º Recrutamento de comandantes e 2.os comandantes
                            
                           
                             
                               
                             
     1 - O recrutamento para os cargos de comandante é feito, por escolha, de entre: 
  a) Superintendentes-chefes ou superintendentes, para os cargos de comandante regional e metropolitano de polícia; 
  b) Superintendentes-chefes ou superintendentes, para o cargo de comandante da UEP; 
  c) Superintendentes, intendentes ou subintendentes para os cargos de comandante distrital de polícia. 
  2 - O recrutamento para os cargos de 2.º comandante é feito, por escolha, de entre: 
  a) Superintendentes ou intendentes, para os cargos de 2.º comandante regional e metropolitano de polícia; 
  b) Superintendentes ou intendentes, para o cargo de 2.º comandante da UEP; 
  c) Intendentes, subintendentes ou comissários para os cargos de 2.º comandante distrital de polícia. 
  3 - O ministro da tutela, sob proposta do director nacional, define por despacho o posto do comandante e do 2.º comandante de cada unidade territorial, em função da complexidade do comando e no respeito pelo disposto nos números anteriores.            
         
   
     
                         
                          
 ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' Artigo 56.º Provimento em comissão de serviço
                            
                           
                             
                               
                             
     1 - O provimento dos cargos de comandante regional, metropolitano, distrital de polícia e da UEP, é feito em comissão de serviço por um período de três anos, renovável, mediante despacho do ministro da tutela, sob proposta do director nacional. 
  2 - A renovação da comissão de serviço é comunicada ao interessado pela entidade competente até 30 dias antes do seu termo, cessando a mesma automaticamente no final do respectivo período na ausência de comunicação, caso em que o dirigente se mantém no exercício de funções de gestão corrente até à tomada de posse do novo titular do cargo. 
  3 - Para efeitos de eventual renovação da comissão de serviço, deve a entidade competente ser informada, com a antecedência mínima de 90 dias do termo de cada comissão, cessando esta automaticamente no fim do respectivo período sempre que não seja dado cumprimento àquela formalidade. 
  4 - Em qualquer momento, as comissões de serviço podem ser dadas por findas por despacho da entidade competente para a nomeação, por sua iniciativa, por proposta do director nacional ou a requerimento do interessado.            
         
   
     
                         
                          
  Artigo 57.º Outros cargos de comando
                            
                           
                             
                               
                             
     1 - O provimento dos cargos de comandante do CI, GOE, CSP, CIEXSS e do GOC é feito por despacho do director nacional, sob proposta do comandante da UEP. 
  2 - O provimento dos cargos de comandante de divisão é feito por despacho do director nacional, sob proposta do respectivo comandante de unidade. 
  3 - O provimento dos cargos de comandante de esquadra é feito por despacho do respectivo comandante regional, metropolitano ou distrital de polícia.            
         
   
     
                         
                          
  Artigo 58.º Cargos de direcção intermédia de 1.º grau
                            
                           
                             
                               
                             
     1 - O recrutamento para cargo de direcção intermédia de 1.º grau é feito em comissão de serviço por um período de três anos, mediante despacho do director nacional, por escolha de entre superintendentes ou funcionários. 
  2 - O recrutamento para os cargos de direcção intermédia de 1.º grau de serviços com atribuições exclusiva ou predominantemente técnico-policiais é feito exclusivamente de entre superintendentes. 
  3 - Os serviços com atribuições exclusiva ou predominantemente policiais são determinados por portaria do ministro da tutela. 
  4 - É aplicável aos dirigentes a que se refere o presente artigo o disposto nos n.os 2 a 4 do artigo 56.º            
      ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('   
   
     
                         
                          
  Artigo 59.º Cargos de direcção intermédia de 2.º grau
                            
                           
                             
                               
                             
     1 - O recrutamento para cargo de direcção intermédia de 2.º grau é feito em comissão de serviço por um período de três anos, mediante despacho do director nacional, por escolha de entre intendentes ou funcionários. 
  2 - O recrutamento para os cargos de direcção intermédia de 2.º grau de serviços com atribuições exclusiva ou predominantemente técnico-policiais é feito exclusivamente de entre intendentes. 
  3 - Ao provimento e recrutamento para estes cargos é aplicável o disposto no n.º 3 do artigo anterior e nos n.os 2 a 4 do artigo 56.º            
         
   
     
                         
                          
TÍTULO IVDisposições financeiras  Artigo 60.º Receitas
                            
                           
                             
                               
                             
     Constituem receitas da PSP: 
  a) As dotações atribuídas pelo Orçamento do Estado; 
  b) O produto da venda de publicações e as quantias cobradas por actividades ou serviços prestados; 
  c) Os juros dos depósitos bancários; 
  d) As receitas próprias consignadas à PSP; 
  e) Os saldos das receitas consignadas; 
  f) Quaisquer outras receitas que lhe sejam atribuídas por lei, contrato ou a outro título.            
         
   
     
                         
                          
  Artigo 61.º Despesas
                            
                           
                             
                               
                             
     Constituem despesas da PSP as que resultem de encargos decorrentes do funcionamento dos seus órgãos e serviços e da actividade operacional, na prossecução das atribuições que lhe estão cometidas.            
         
   
     
                         
                          
  Artigo 62.º Recrutamento excepcional
                            
                           
                             
                               
                             
     1 - Por despacho do ministro da tutela, sob proposta do director nacional, pode o oficial de polícia com formação e experiência adequadas desempenhar funções correspondentes ao posto imediatamente superior. 
  2 - O pessoal provido nos termos do número anterior tem os direitos e deveres inerentes à função desempenhada. 
  3 - O pessoal provido retoma a remuneração devida no posto de origem, quando cessar as funções que desempenhava, sendo-lhe contado o tempo de permanência no posto em que tiver sido provido, para efeitos de mudança de escalão e antiguidade. 
  4 - Se, durante o tempo em que estiver provido no posto imediato, ocorrer a sua promoção, o elemento manterá o escalão em que se encontrar até que, pelo normal desenvolvimen','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('to da progressão esse escalão lhe competir, devendo, para efeitos de antiguidade, ser colocado na posição que lhe competiria no normal desenvolvimento da carreira.            
         
   
     
                         
                          
  Artigo 63.º Taxas
                            
                           
                             
                               
                             
     A actividade da PSP pode implicar a aplicação de taxas e a cobrança de despesas a cargo de entidades que especialmente beneficiem com aquela actividade, nos termos a regular em diploma próprio.            
         
   
     
                         
                          
TÍTULO VDisposições transitórias e finais  Artigo 64.º Disposição transitória
                            
                           
                             
                               
                             
     A organização e funcionamento dos serviços sociais são regulados por diploma próprio.            
         
   
     
                         
                          
  Artigo 65.º Regulamentação
                            
                           
                             
                               
                             
     1 - São regulados por diploma próprio: 
  a) A organização e funcionamento do ISCPSI e da EPP; 
  b) A aplicação de taxas e a cobrança de despesas a cargo de entidades que especialmente beneficiem com a actividade da PSP; 
  c) O estatuto remuneratório do director nacional. 
  2 - A prestação e o pagamento dos serviços requisitados à PSP nos termos dos artigos 15.º e 16.º da presente lei são objecto de portaria conjunta do ministro da tutela, do membro do Governo responsável pela área das finanças e, quando aplicável, do membro do Governo com a tutela da entidade requisitante. 
  3 - O número, as competências e a estrutura interna dos serviços das unidades orgânicas, bem como o quadro de dirigentes da PSP, são definidos por portaria, nos termos da Lei n.º 4/2004, de 15 de Janeiro. 
  4 - São aprovados por portaria do ministro da tutela: 
  a) A área de responsabilidade da PSP, no caso de atribuições simultaneamente cometidas à Guarda Nacional Republicana, bem como dos comandos territoriais de polícia e respectivas subunidades; 
  b) As condições em que o pessoal da PSP com funções policiais pode ser afecto a organismos de interesse público; 
  c) Os serviços com atribuições exclusiva ou predominantemente policiais; 
  d) A criação e extinção de subunidades dos comandos territoriais de polícia e da UEP; 
  e) A criação e extinção e o funcionamento dos serviços dos comandos territoriais de polícia, da UEP e dos estabelecimentos de ensino. 
  5 - São regulados por despacho do ministro da tutela: 
  a) Os tipos de armas em uso pela PSP, bem como as regras do respectivo emprego; 
  b) O regulamento da Inspecção.            
         
   
     
                         
                   ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
  Artigo 66.º Transferência de símbolos
                            
                           
                             
                               
                             
     1 - A UEP é a herdeira dos estandartes nacionais do CI, GOE e CSP, incluindo as respectivas condecorações atribuídas. 
  2 - O CI, GOE e CSP mantêm o direito a brasão de armas e a bandeira heráldica. 
  3 - Os demais símbolos do CI, GOE e CSP passam, para todos os efeitos, a integrar o património histórico da UEP.            
         
   
     
                         
                          
  Artigo 67.º Norma revogatória
                            
                           
                             
                               
                             
     É revogada a Lei n.º 5/99, de 27 de Janeiro, com excepção: 
  a) Dos artigos 4.º e 6.º, cuja revogação produz efeitos com a entrada em vigor de uma nova lei de segurança interna; 
  b) Dos artigos 88.º, 89.º, 90.º a 94.º e 103.º, cuja revogação produz efeitos com a entrada em vigor de um novo estatuto do pessoal da PSP; 
  c) Do artigo 105.º, cuja revogação produz efeitos com a entrada em vigor da portaria referida no n.º 3 do artigo 65.º 
  Consultar o  Lei Orgânica da PSP (actualizado face ao diploma em epígrafe)            
         
   
     
                         
                          
  Artigo 68.º Entrada em vigor
                            
                           
                             
                               
                             
     A presente lei entra em vigor no prazo de 30 dias, com excepção do artigo 65.º que entra em vigor no dia seguinte ao da publicação. 
  Aprovada em 19 de Julho de 2007. 
  O Presidente da Assembleia da República, Jaime Gama. 
  Promulgada em 20 de Agosto de 2007. 
  Publique-se. 
  O Presidente da República, Aníbal Cavaco Silva. 
  Referendada em 20 de Agosto de 2007. 
  O Primeiro-Ministro, José Sócrates Carvalho Pinto de Sousa.','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:20  
    
  DL n.º 83/2012, de 30 de Março  (versão actualizada) LEI ORGÂNICA DO INSTITUTO DA SEGURANÇA SOCIAL, I. P.    
    
 
Contém as seguintes alterações:   - DL n.º 167/2013, de 30 de Dezembro   - DL n.º 63/2026, de 26 de Fevereiro  
                         
                          
SUMÁRIOAprova a orgânica do Instituto da Segurança Social, I. P. - Este diploma foi revogado pelo(a) Decreto-Lei n.º 63/2026, de 26 de Fevereiro!
Decreto-Lei n.º 83/2012, de 30 de março 
  No âmbito do Compromisso Eficiência, o XIX Governo Constitucional determinou as linhas gerais do Plano de Redução e Melhoria da Administração Central (PREMAC), afirmando que o primeiro e mais importante impulso do Plano deveria, desde logo, ser dado no processo de preparação das leis orgânicas dos ministérios e dos respetivos serviços. 
  Trata-se de algo absolutamente estruturante, por um lado, para o início de uma nova fase da reforma da Administração Pública, no sentido de a tornar eficiente e racional na utilização dos recursos públicos e, por outro, para o cumprimento dos objetivos de redução da despesa pública a que o país está vinculado. Com efeito, mais do que nunca, a concretização simultânea dos objetivos de racionalização das estruturas do Estado e de melhor utilização dos seus recursos humanos é crucial no processo de modernização e de otimização do funcionamento da Administração Pública. 
  Importava decididamente repensar e reorganizar a estrutura do Estado, no sentido de lhe dar uma maior coerência e capacidade de resposta no desempenho das funções que deverá assegurar, eliminando redundâncias e reduzindo substancialmente os seus custos de funcionamento. 
  Ao Instituto da Segurança Social, I. P. (ISS, I. P.), como instituto público central no funcionamento do sistema de segurança social, é requerida uma reestruturação à sua orgânica, permitindo dinamizar a sua ação e potenciar ganhos nos resultados obtidos. Garantindo a abrangência necessária às atribuições do ISS, I. P., desenvolve-se um reajustamento nos órgãos que o compõem, tendo como objetivo primeiro a correta e adequada delimitação de competências, possibilitando a efetiva interação e cooperação entre os órgãos reestruturados e criados. 
  Assim: 
  Ao abrigo do disposto no n.º 1 do artigo 16.º da  Lei nº 3/2004, de 15 de janeiro, e nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta o seguinte:
  Artigo 1.º 
Natureza - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O Instituto da Segurança Social, I. P., abreviadamente designado por ISS, I. P., é um instituto público de regime especial, nos termos da lei, integrado na administração indireta do Estado, dotado de autonomia administrativa e financeira e património próprio. 
  2 - O ISS, I. P., prossegue atribuições do Ministério da Solidariedad','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e, Emprego e Segurança Social, sob superintendência e tutela do respetivo ministro.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 167/2013, de 30 de Dezembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 83/2012, de 30 de Março   
     
                         
                          
  Artigo 2.º Jurisdição territorial e sede - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O ISS, I. P., é um organismo central, com jurisdição sobre todo o território nacional, sem prejuízo das atribuições e competências das Regiões Autónomas dos Açores e da Madeira. 
  2 - O ISS, I. P., tem sede em Lisboa. 
  3 - O ISS, I. P., dispõe de dezoito serviços desconcentrados a nível distrital, designados centros distritais. 
  4 - O ISS, I. P., dispõe ainda de um serviço designado Centro Nacional de Pensões.            
         
   
     
                         
                          
  Artigo 3.º Missão e atribuições - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O ISS, I. P., tem por missão a gestão dos regimes de segurança social, incluindo o tratamento, recuperação e reparação de doenças ou incapacidades resultantes de riscos profissionais, o reconhecimento dos direitos e o cumprimento das obrigações decorrentes dos regimes de segurança social e demais subsistemas da segurança social, incluindo o exercício da ação social, bem como assegurar a aplicação dos acordos internacionais no âmbito do sistema da segurança social. 
  2 - São atribuições do ISS, I. P.: 
  a) Gerir as prestações do sistema de segurança social e dos seus subsistemas; 
  b) Garantir a realização dos direitos e promover o cumprimento das obrigações dos beneficiários do sistema de segurança social; 
  c) Arrecadar as receitas do sistema de segurança social, assegurando o cumprimento das obrigações contributivas; 
  d) Participar às secções de processo executivo do Instituto da Gestão Financeira da Segurança Social, I. P. (IGFSS, I. P.), as dívidas à segurança social, designadamente por contribuições e respetivos juros de mora; 
  e) Reclamar os créditos da segurança social em sede de processos de insolvência e de execução de índole fiscal, cível e laboral, bem como requerer, na qualidade de credor, a declaração de insolvência, em articulação com o IGFSS, I. P.; 
  f) Assegurar, no seu âmbito de atuação, o cumprimento das obrigações decorrentes dos instrumentos internacionais de segurança social; 
  g) Celebrar acordos que prevejam exceções às normas relativas à determinação da legislação aplicável constantes de instrumentos internacionais de coordenação e decidir sobre a vinculação, manutenção ou ise','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nção do vínculo à legislação portuguesa de segurança social, no quadro, designadamente, dos referidos instrumentos internacionais, sem prejuízo das competências próprias do Ministério dos Negócios Estrangeiros (MNE); 
  h) Assegurar a atribuição das prestações devidas por aplicação dos instrumentos internacionais de segurança social em matéria de acidentes de trabalho e de doenças profissionais; 
  i) Promover a execução das disposições financeiras estabelecidas nos instrumentos internacionais de segurança social e colaborar na sua execução, quando se trate de prestações que em Portugal não sejam do âmbito do sistema de segurança social; 
  j) Promover a liquidação e pagamento das prestações a cargo e por conta de instituições estrangeiras, no quadro da aplicação dos instrumentos internacionais de segurança social; 
  k) Apoiar o Conselho Nacional para as Políticas de Solidariedade, Voluntariado, Família, Reabilitação e Segurança Social na promoção, desenvolvimento e execução das políticas de garantia e valorização do voluntariado; 
  l) Desenvolver e executar as políticas de ação social, bem como desenvolver medidas de combate à pobreza e de promoção da inclusão social; 
  m) Desenvolver a cooperação com as instituições particulares de solidariedade social e exercer, nos termos da lei, a sua tutela, bem como desenvolver a cooperação com outras entidades; 
  n) Assegurar o apoio social às famílias, através do financiamento direto, nos termos da lei; 
  o) Desenvolver e apoiar iniciativas que tenham por finalidade a melhoria das condições de vida das famílias e a promoção da igualdade de oportunidades, designadamente as dirigidas à infância, à juventude, ao envelhecimento ativo, dependência, imigração, minorias étnicas e outros grupos em situação de vulnerabilidade; 
  p) Assegurar, nos termos da lei, assessoria técnica aos tribunais em matéria de promoção e proteção de crianças e jovens em perigo e tutelar cível; 
  q) Promover o licenciamento dos serviços e estabelecimentos de apoio social; 
  r) Celebrar acordos ou protocolos de cooperação; 
  s) Avaliar e fixar as incapacidades em matéria de doenças emergentes de riscos profissionais e assegurar a prestação dos cuidados médicos e medicamentosos necessários, bem como as compensações, indemnizações e pensões por danos emergentes de riscos profissionais, por incapacidade temporária ou permanente; 
  t) Participar na Revisão e Atualização da Tabela Nacional de Incapacidades por Acidentes de Trabalho e Doenças Profissionais e assegurar o apoio necessário aos respetivos trabalhos; 
  u) Exercer a ação fiscalizadora no cumprimento dos direitos e obrigações dos beneficiários e contribuintes do sistema de segurança social, das instituições particulares de solidariedade social e de outras entidades privadas que exerçam atividades de apoio social; 
  v) Exercer os poderes sancionatórios no âmbito dos ilícitos de mera ordenação social relativos aos estabelecimentos de apoio social, a beneficiários e contr','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ibuintes, nos termos legais; 
  w) Assegurar nos termos da lei, as ações necessárias à eventual aplicação dos regimes sancionatórios referentes a infrações criminais praticadas por beneficiários e contribuintes no âmbito do sistema de segurança social; 
  x) Intervir na adoção, nos termos da lei, bem como no âmbito da adoção internacional, como autoridade central; 
  y) Assegurar, nos termos da lei, a concessão de proteção jurídica; 
  z) Promover a divulgação da informação e as ações adequadas ao exercício do direito de informação e de reclamação dos interessados, bem como a dignificação da imagem do sistema de segurança social; 
  aa) Assegurar as relações externas em matéria das suas atribuições, sem prejuízo das atribuições da Direção-Geral de Segurança Social, e das competências próprias do MNE; 
  bb) Assegurar a promoção de respostas e o apoio à produção de respostas na área da inclusão social, com vista a prevenir e combater as situações indiciadas e ou sinalizadas de crianças e jovens em risco de exclusão social, compaginando a mobilização de medidas já existentes com medidas específicas; 
  cc) Emitir orientações técnicas no âmbito das suas atribuições. 
  3 - No âmbito da alínea r)do número anterior, os acordos ou protocolos de cooperação atípicos carecem de homologação por parte da tutela.            
         
   
     
                         
                          
  Artigo 4.º Órgãos - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     São órgãos do ISS, I. P.: 
  a) O conselho diretivo; 
  b) O fiscal único; 
  c) O conselho consultivo; 
  d) O conselho médico; 
  e) O conselho de apoio para assuntos de proteção contra os riscos profissionais.            
         
   
     
                         
                          
  Artigo 5.º Conselho diretivo - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O conselho diretivo é composto por um presidente, por um vice-presidente e por dois vogais, cabendo ao presidente voto de qualidade. 
  2 - Sem prejuízo das competências conferidas por lei ou que nele sejam delegadas ou subdelegadas, compete ao conselho diretivo, no âmbito da orientação e gestão do ISS, I. P.: 
  a) Dinamizar e gerir as prestações do sistema de segurança social e dos seus subsistemas; 
  b) Assegurar a regularidade da relação contributiva de segurança social, bem como constituir hipotecas legais e autorizar o respetivo distrate, com exceção das que se inserem no âmbito do processo executivo; 
  c) Promover a ação inspetiva e fiscalizadora do cumprimento dos direitos e obrigações dos beneficiários e contribuintes do sistema de segurança social, das instituições particulares de solidariedade','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' social e de outras entidades privadas que exerçam atividades de apoio social; 
  d) Assegurar a aplicação dos instrumentos internacionais em matéria de segurança social; 
  e) Promover medidas de modernização administrativa, colaborar na definição do sistema de informação da segurança social e avaliar a respetiva eficácia e assegurar, em articulação com o Instituto de Informática, I. P., o funcionamento do sistema de informática e comunicações do ISS, I. P.; 
  f) Aplicar coimas e sanções acessórias às contraordenações praticadas por beneficiários, contribuintes e estabelecimentos de apoio social.            
         
   
     
                         
                          
  Artigo 6.º Fiscal único - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     O fiscal único é designado e tem as competências previstas na lei quadro dos institutos públicos.            
         
   
     
                         
                          
  Artigo 7.º Conselho consultivo - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O conselho consultivo é o órgão de consulta, apoio e participação na definição das linhas gerais de atuação do ISS, I. P., e nas tomadas de decisão do conselho diretivo. 
  2 - O conselho consultivo é composto por: 
  a) Um presidente; 
  b) Os dirigentes máximos dos serviços e instituições do sistema de segurança social; 
  c) Um representante de cada um dos parceiros sociais; 
  d) O presidente da Confederação Nacional das Instituições de Solidariedade (CNIS); 
  e) O presidente da União das Misericórdias Portuguesas; 
  f) O presidente da União das Mutualidades Portuguesas; 
  g) Um representante da Associação Nacional de Aposentados, Pensionistas e Reformados (MODERP); 
  h) Um representante da Confederação Nacional de Reformados, Pensionistas e Idosos (MURPI). 
  3 - Podem ainda fazer parte do conselho consultivo personalidades de reconhecido mérito na área de atribuições do ISS, I. P. 
  4 - Os membros do conselho consultivo são designados pelo membro do Governo da tutela pelo período de três anos, renovável, mediante proposta das organizações que o integram. 
  5 - O presidente do conselho consultivo indica o membro que o substitui nas suas faltas ou impedimentos. 
  6 - Os membros do conselho diretivo responsáveis pelas matérias constantes da ordem de trabalhos devem participar nas reuniões do conselho consultivo, sem direito a voto. 
  7 - Podem ainda participar nas reuniões do conselho consultivo, nas mesmas condições, os restantes membros do conselho diretivo. 
  8 - Sem prejuízo das competências conferidas por lei, compete ao conselho consultivo pronunciar-se sobre as grandes linhas de orientação do IS','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('S, I. P.            
         
   
     
                         
                          
  Artigo 8.º Conselho médico - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O conselho médico é o órgão de consulta, apoio e participação para as questões de natureza médico-funcional, no âmbito do sistema de verificação de incapacidades que funciona junto do ISS, I. P. 
  2 - O conselho médico é composto por: 
  a) Os assessores técnicos de coordenação do sistema de verificação de incapacidades; 
  b) Um clínico da área de doenças emergentes de riscos profissionais, a designar pelo conselho diretivo; 
  c) Dois representantes do ISS, I. P., também designados pelo conselho diretivo, que indica de entre estes o respetivo presidente. 
  3 - Podem ainda integrar o conselho médico os assessores técnicos de coordenação das Regiões Autónomas dos Açores e da Madeira, nos termos a definir em protocolo a celebrar entre os organismos regionais competentes e o ISS, I. P. 
  4 - Podem participar nas reuniões do conselho médico, sem direito a voto, por convocação do seu presidente, entidades e personalidades de reconhecido mérito na respetiva área de competências, cuja presença seja considerada necessária para esclarecimento dos assuntos em apreciação. 
  5 - O conselho médico pode funcionar em comissões especializadas por áreas especializadas científicas e criar uma comissão permanente composta pelos dois representantes do ISS, I. P., e dois dos restantes membros, nos termos fixados em regulamento interno por si proposto e a aprovar pelo conselho diretivo. 
  6 - Sem prejuízo das competências conferidas por lei, compete ao conselho médico: 
  a) Pronunciar-se sobre as questões de natureza médico-funcional suscitadas pela aplicação da legislação reguladora da verificação de incapacidades; 
  b) Pronunciar-se e emitir recomendações sobre procedimentos relativos à salvaguarda dos princípios deontológicos e à garantia da defesa da saúde e equilíbrio dos doentes, bem como à luta contra o acesso abusivo a prestações, de forma a contribuir para a qualidade e o rigor dos atos de perícia médica; 
  c) Pronunciar-se sobre a avaliação do funcionamento do sistema, sugerindo a definição de critérios e indicadores de avaliação dos procedimentos e resultados; 
  d) Promover a formação dos peritos médicos, propondo ao conselho diretivo a sua participação ou a realização de reuniões, seminários, encontros e conferências de carácter científico ou técnico especializado; 
  e) Apoiar o conselho diretivo no desenvolvimento de articulação com áreas especializadas no domínio médico e médico-legal; 
  f) Receber e pronunciar-se sobre reclamações e exposições que lhe sejam apresentadas; 
  g) Apresentar ao conselho diretivo sugestões ou propostas consideradas convenientes à garantia de uma melhor eficiência funcional do siste','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ma de verificação de incapacidades; 
  h) Elaborar o respetivo regulamento. 
  7 - A participação no conselho médico não é remunerada.            
         
   
     
                         
                          
  Artigo 9.º 
Conselho de apoio para assuntos de proteção contra os riscos profissionais - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O conselho de apoio para assuntos de proteção contra os riscos profissionais, adiante designado por conselho, é o órgão de apoio à gestão, para matérias relacionadas com a proteção contra os riscos profissionais. 
  2 - O conselho é composto pelo: 
  a) Presidente do conselho diretivo, que preside; 
  b) Responsável pela unidade orgânica do ISS, I. P., com competência na área de ação na doença e proteção contra os riscos profissionais; 
  c) Quatro membros, representando em igual número os beneficiários e as entidades patronais contribuintes, designados pelo membro do Governo da tutela, por um período de três anos, sob proposta das associações sindicais e patronais com assento no Conselho Permanente de Concertação Social. 
  3 - O conselho reúne, ordinariamente, uma vez por mês e, extraordinariamente, sempre que o presidente o convoque, por sua iniciativa ou a solicitação de um terço dos seus membros.
  4 - Aos membros do conselho representantes dos beneficiários compete o acompanhamento das atividades da unidade orgânica com competência na área de ação na doença e proteção contra os riscos profissionais e contribuir para a preparação dos documentos técnicos necessários às reuniões do conselho.
  5 - Os membros do conselho representantes dos beneficiários e das entidades patronais contribuintes têm direito a senhas de presença por reunião, nos termos a fixar por despacho dos membros do Governo responsáveis pelas áreas das finanças e da segurança social.
  6 - O presidente do conselho é substituído nas suas faltas e impedimentos pelo responsável pela unidade orgânica com a competência na área de ação na doença e proteção contra os riscos profissionais. 
  7 - Sem prejuízo das competências conferidas por lei, compete ao conselho: 
  a) Dar parecer e prestar informações sobre todas as questões que lhe sejam submetidas pelo conselho diretivo; 
  b) Emitir recomendações; 
  c) Acompanhar a execução dos programas e planos de ação; 
  d) Desenvolver as ações necessárias à promoção, qualificação e execução das matérias do âmbito dos riscos profissionais.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 167/2013, de 30 de Dezembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 83/2012, de 30 de Março   
     
                         
                          
  Artigo 10.º Organização interna - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
      ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                     
                             
                               
                             
     A organização interna do ISS, I. P., é a prevista nos respetivos estatutos.            
         
   
     
                         
                          
  Artigo 11.º Estatuto dos membros do conselho diretivo - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     Os membros do conselho diretivo são equiparados, para efeitos remuneratórios, a gestores públicos.            
         
   
     
                         
                          
  Artigo 12.º Receitas - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O ISS, I. P., dispõe das receitas provenientes de dotações que lhe forem atribuídas no Orçamento da Segurança Social. 
  2 - O ISS, I. P., dispõe ainda das seguintes receitas próprias: 
  a) Os rendimentos de bens próprios; 
  b) Os benefícios prescritos; 
  c) O reembolso das prestações do sistema de segurança social; 
  d) O produto das coimas legalmente previstas; 
  e) As comparticipações pela utilização dos estabelecimentos integrados ou serviços sociais; 
  f) Os subsídios de quaisquer entidades, públicas ou privadas, doações, legados ou heranças; 
  g) Os valores provenientes de organismos nacionais e estrangeiros para pagamento de benefícios, ao abrigo de instrumentos internacionais de segurança social, e quaisquer outros valores resultantes da execução destes instrumentos internacionais; 
  h) As verbas provenientes da prestação de serviços, designadamente de transferências no âmbito da União Europeia; 
  i) A alienação de imobilizações corpóreas e o produto da alienação ou cedência de direitos do seu património; 
  j) A amortização, resgate e alienação de imobilizações financeiras e os juros de depósitos bancários; 
  k) Quaisquer outras receitas que lhe sejam atribuídas por lei, contrato ou outro título. 
  3 - Os saldos das receitas referidas no número anterior, verificados no final de cada ano, transitam para o ano seguinte, nos termos previstos no decreto-lei de execução orçamental anual.            
         
   
     
                         
                          
  Artigo 13.º Despesas - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     Constituem despesas do ISS, I. P., as que resultem de encargos decorrentes da prossecução das respetivas atribuições.            
         
   
     
                         
                          
  Artigo 14.º Património - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
 ','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                           
                           
                             
                               
                             
     O património do ISS, I. P., é constituído pela universalidade de bens, direitos e obrigações de que seja titular.            
         
   
     
                         
                          
  Artigo 15.º Cargos dirigentes intermédios - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - São cargos de direção intermédia de 1.º grau do ISS, I. P., os diretores de segurança social, os diretores-adjuntos de segurança social, os diretores de departamento e os diretores de gabinete. 
  2 - São cargos de direção intermédia de 2.º grau do ISS, I. P., os diretores de unidade, os diretores de núcleo e o secretário do conselho diretivo. 
  3 - A remuneração base dos cargos de direção intermédia identificados nos números anteriores é determinada em percentagem da remuneração base do vogal do conselho diretivo do ISS, I. P., nas seguintes proporções: 
  a) Diretores de segurança social, 80 ; 
  b) Diretores-adjuntos de segurança social, 70 ; 
  c) Diretores de departamento e diretores de gabinete, 65 ; 
  d) Diretores de unidade, 55 ; 
  e) Diretores de núcleo, 50 ; 
  f) Secretário do conselho diretivo, 50 . 
  4 - As despesas de representação dos cargos de direção intermédia de 1.º e 2.º graus do ISS, I. P., são determinadas em percentagem das despesas de representação do vogal do conselho diretivo do ISS, I. P., nos termos do número anterior.            
         
   
     
                         
                          
  Artigo 16.º 
Designação de cargos de dirigentes intermédios - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O recrutamento dos diretores de segurança social e do diretor de segurança social do Centro Nacional de Pensões faz-se de entre indivíduos com licenciatura concluída à data da abertura do concurso há pelo menos seis anos, aplicando-se as regras de recrutamento e seleção previstas para os cargos de direção superior no Estatuto do Pessoal Dirigente.
  2 - O recrutamento dos diretores adjuntos de segurança social e do diretor adjunto de segurança social do Centro Nacional de Pensões faz-se de entre indivíduos com licenciatura concluída à data da abertura do concurso há pelo menos quatro anos, aplicando-se as regras de recrutamento e seleção previstas para os cargos de direção superior no Estatuto do Pessoal Dirigente.
  3 - As competências cometidas ao membro do Governo no âmbito do procedimento concursal referido no número anterior podem ser delegadas no conselho diretivo.            
         
  Contém as alterações introduzidas pelos seguintes di','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('plomas:   - DL n.º 167/2013, de 30 de Dezembro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 83/2012, de 30 de Março   
     
                         
                          
  Artigo 17.º Poderes de autoridade - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - O pessoal do ISS, I. P., quando no exercício de funções de acompanhamento e supervisão das instituições particulares de solidariedade social e de outras entidades privadas que exerçam atividades de apoio social e, ainda, no exercício de funções de fiscalização, goza das seguintes prorrogativas: 
  a) Direito de acesso e livre trânsito nos termos da lei, pelo tempo e horário necessários ao desempenho das suas funções, em todos os serviços e instalações das entidades públicas e privadas sujeitas ao exercício das suas atribuições; 
  b) Obter, das entidades auditadas para apoio nas ações de controlo e auditoria em curso, a cedência de instalações adequadas, material e equipamento próprio, bem como a colaboração de pessoal que se mostre indispensável; 
  c) Requisitar a colaboração necessária das autoridades policiais e administrativas para o exercício das suas funções; 
  d) Promover, nos termos legais, a selagem de quaisquer instalações, dependências, cofres ou móveis, bem como a apreensão, requisição ou reprodução de documentos em poder das entidades alvo de controlo e auditoria ou do seu pessoal, quando isso se mostre indispensável à realização da ação para o que deve ser levantado o competente auto, dispensável no caso de simples reprodução de documento; 
  e) Requisitar para exame, consulta e junção aos autos livros, documentos, registos, arquivos e outros elementos pertinentes em poder das entidades cuja atividade seja objeto da sua ação de controlo e auditoria. 
  2 - Ao pessoal referido no número anterior é aplicável o regime jurídico da atividade inspetiva dos serviços de inspeção, auditoria e fiscalização da administração central do Estado, no que se refere ao regime de incompatibilidades e impedimentos, bem como ao direito a apoio em processos judiciais. 
  3 - O pessoal do ISS, I. P., no exercício das prerrogativas previstas no presente artigo, é portador de um documento de identificação próprio, de modelo a fixar por portaria do membro do Governo responsável pela área da segurança social, devendo exibi-lo no exercício das suas funções.            
         
   
     
                         
                          
  Artigo 18.º Norma transitória - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     1 - A estrutura de missão Programa para a Inclusão e Cidadania (PIEC) extingue-se no término do ano letivo 2011/2012. 
  2 - Durante a vigência do P','454');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rograma de Assistência Económica e Financeira, da aplicação das regras de fixação de remuneração estabelecidas pelo presente diploma não pode resultar um aumento da remuneração efetivamente paga aos cargos de direção intermédia, designados ou a designar, tendo por referência a remuneração atribuída à data de entrada em vigor do presente decreto-lei, sem prejuízo do eventual exercício da opção pelo vencimento do lugar de origem nas novas designações.            
         
   
     
                         
                          
  Artigo 19.º Norma revogatória - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     É revogado o  Decreto-Lei nº 214/2007, de 29 de maio, com as alterações introduzidas pelo Decreto-Lei n.º 163/2008, de 8 de agosto.            
         
   
     
                         
                          
  Artigo 20.º Entrada em vigor - revogado - Decreto-Lei n.º 63/2026, de 26 de Fevereiro
                            
                           
                             
                               
                             
     O presente diploma entra em vigor no 1.º dia do mês seguinte ao da sua publicação. 
  
  Visto e aprovado em Conselho de Ministros de 1 de março de 2012. - Pedro Passos Coelho - Luís Filipe Bruno da Costa de Morais Sarmento - Luís Pedro Russo da Mota Soares. 
